INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-1FW', 'ケーブルハンガー(ループタイプ)ダブルタイプ', '二重天井等、吊りボルトへのVVFケーブルの取り付け(支持)に使用します。ハンガー部分がR形状のため、ケーブルを引く時の抵抗が少なく、ケーブル引っ張り時等にハンガーにかかる力に対して変形しにくい強固なループ形状です。吊りボルトへの取り付けワンタッチ! W3/8-W1/2ボルト兼用。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-1FW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCH-B4', 'バインドハンガー® (丸バインドタイプ) 接着タイプ', '天井面や壁面への先行配線等に使用するケーブル用ハンガーです。接着剤固定タイプですから施工場所を選びません。ケーブルがシッカリ固定できる丸バインド! バインド線長さ130mm。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCH-B4', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGSCH-1', 'ケーブルハンガー(鋲打機用)', '壁面、天井面へのケーブルの取り付け(支持)に使用します。鋲打機固定タイプですのでスピーディーに施工ができます。電気・ガス式鋲打機用。鋲打ち機で施工がスピーディー!', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGSCH-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'ACH-C3Z', 'ケーブルハンガー(ALC・木材用)', 'ALC・木材へのVVFケーブル取り付け (支持) に使用します。ケーブル等の垂が気になる場合や増線が必要な場合に結束バンドによる固定ができます。取り付け簡単! 釘を打ち込むだけ! ビス釘付。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=ACH-C3Z', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDZH-50', '貫通用断熱材(半割れタイプ)', '(ケーブル用) 恒温室等に使用されている断熱パネルのケーブル貫通箇所に使用する断熱材です。ウレタンでの処理に比べ使用量が少なく済み、施工も簡単です。施工がし易い半割れタイプ。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDZH-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDZH3-50', '貫通用断熱材(半割れタイプ)', '(吊りボルト用W3/8) 恒温室等に使用されている断熱パネルのケーブル貫通箇所に使用する断熱材です。ウレタンでの処理に比べ使用量が少なく済み、施工も簡単です。施工がし易い半割れタイプ。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDZH3-50', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDZK-T10', '貫通用断熱材用さや管(半割れタイプ用)', '貫通用断熱材(半割れタイプ)を使用する場合のさや管として使用します。盤用コネクタや2号コネクタが取り付け可能です。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDZK-T10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
