INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-RS3', '楽打ちインサートスティック', 'デッキプレートへのインサート取り付けが立ったまま行えるので、作業が速く足腰への負担も軽減されます。スティックにインサートを入れるだけで取り付け準備完了。デッキプレートの穴に差し込みスティックを押し込むだけです。省力工具。カラー・ヘッダーインサート(デッキプレート用・ばねタイプ)。NDB-3型専用。透明なのでインサートの数や色が確認できます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-RS3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
