INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DNW-1', '半月ノコ (引刃)', 'せっこうボード・合板等へのボックス取付穴の切り抜きに最適, 小型で軽量, ナイフ感覚の使い易いハンディータイプ, 切り込み穴不要! 多用途な丸刃と直刃の両刃, すべりにくいゴムグリップ, 樹脂ケース付, 刃の交換が簡単にできる替刃式, 直刃部は引刃とケーブルを傷つけにくい押刃, 適用: せっこうボード・合板, 一般木材・塩ビパイプ等', 3510, 'https://dummyimage.com/200x200/cccccc/000.png&text=DNW-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
