INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-FM28', 'ハンディーFカッター28', 'CD管・PF管、モール等、様々な物を手軽に切断可能, ベルト掛けできるケース付, カッターの取り出しスムーズ, 衝撃に強い樹脂ケース, ロック機構も備える, 全面刃で長持ち2倍, 切れ味が悪くなったら刃を反転して使用可能, 刃は切れ味鋭いステンレス刃を使用, デンコーマックの2連ケースに収納可能, 適合: CD管・PF管14~28, プラモール・Eモール0号~3号, デンコープロテクタ1号~3号, ジャンボモール12.16型, 外径φ37迄, 断面寸法27×27mm迄', 6950, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-FM28', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-FM28H', 'ハンディーFカッター28 (本体のみ)', '本体のみ, CD管・PF管、モール等、様々な物を手軽に切断可能, ベルト掛けできるケース付, カッターの取り出しスムーズ, 衝撃に強い樹脂ケース, ロック機構も備える, 全面刃で長持ち2倍, 切れ味が悪くなったら刃を反転して使用可能, 刃は切れ味鋭いステンレス刃を使用, デンコーマックの2連ケースに収納可能, 適合: CD管・PF管14~28, プラモール・Eモール0号~3号, デンコープロテクタ1号~3号, ジャンボモール12.16型, 外径φ37迄, 断面寸法27×27mm迄', 6320, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-FM28H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
