INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-V27', 'エンビ管カッター27', '本体:アルミ合金製、刃:ステンレス製。塩ビ管・合成樹脂製可とう管等、樹脂管専用の切断工具です。軽量タイプ、切れ味鋭いステンレス刃を採用、ラチェット式だからラクに切断できます。刃はワンタッチ開口機構により片手で開口できます。適合切断外径:φ27迄(VE-22迄)。全長:195mm、重量:326g。', 11400, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-V27', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-V42', 'エンビ管カッター42 (アタッチメント付)', '本体:アルミ合金製、刃:ステンレス製。塩ビ管・合成樹脂製可とう管等、樹脂管専用の切断工具です。軽量タイプ、切れ味鋭いステンレス刃を採用、ラチェット式だからラクに切断できます。刃はワンタッチ開口機構により片手で開口できます。開口径調整ストッパーでワンタッチ開口のサイズを27と42に設定できます。添付の専用アタッチメントにより配線用モール・プロテクタ等の直角、斜め45°切断が正確にできます。適合切断外径:φ42迄(VE-36迄)。全長:234mm、重量:458g。', 13400, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-V42', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-V63', 'エンビ管カッター63', '本体:アルミ合金製、刃:SK鋼材。塩ビ管・合成樹脂製可とう管等、樹脂管専用の切断工具です。軽量タイプ、ラチェット式だからラクに切断できます。適合切断外径:φ63迄(VE-54迄)。全長:299mm、重量:647g。', 19600, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-V63', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
