INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-V114', 'エンビ管カッター (大口径用)', '本体:アルミ合金製、刃:SK鋼材。塩ビ管・合成樹脂製可とう管等、樹脂管専用の切断工具です。管の外径がφ48～φ114迄対応の大口径用。ベアリング搭載ローラーを4個使用しスムーズな回転により大口径の管も容易に切断可能。直角に切断でき、切りくずも発生しない。脚立を固定台にして切断作業が可能。適合切断外径:φ48～φ114迄(VE-100迄)。重量:約2.5kg。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-V114', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
