INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PYPG-75100', '換気パイプカットガイド', 'エンビ管カッター(大口径用)を使用して換気パイプ(サイズ75、100)を切断する場合に生じる管のたわみ防止に使用します。磁石入りの取っ手で本体を管の切断したい部分までスライド可能。75サイズガイドと100サイズアダプター、取っ手のセット品。全ての部材をセット可能なのでコンパクトに持ち運び可能。適合管:換気パイプ(75-100)。適合工具:MC-V114。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=PYPG-75100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-OP', 'ワゴンモールカッター', 'ラチェット式でラクラク切断できるワゴンモール用カッターです。片手でワンタッチ開口。45°斜め切りも正確に、簡単に切断可能。適合ワゴンモール:OP-3型～OP-10型。全長:317mm、重量:666g。', 30100, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-OP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-OPH', 'ワゴンモールカッター替刃', 'ステンレス製。MC-OP用。全長:113mm。', 9500, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-OPH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GC-80', 'スッキリラインカッターE専用', 'ラチェット式でラクラク切断できるスッキリラインE専用のカッターです。スッキリラインEのカバーとベースが同時に切断可能。片手でワンタッチ開口。GK-80E型を切断する場合は、先端のスペーサーを起こしてスッキリラインをセットして使用。適合:スッキリラインE(GK-70E-80E型)。全長:308mm、重量:693g。', 18400, 'https://dummyimage.com/200x200/cccccc/000.png&text=GC-80', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GC-80H', 'スッキリラインカッターE専用替刃', 'GC-80用。', 7400, 'https://dummyimage.com/200x200/cccccc/000.png&text=GC-80H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-MD', 'モールダクト用 マルチカッター', 'ラチェット式でラクラク切断可能。片手でワンタッチ開口。モールダクトの他、様々な物が切断可能。適合:モールダクト(40~70型、パイプ70型は除く)、ミラダクト(40,60型)、プラモール、Eモール・Cモール、デンコープロテクタ、ワゴンモール(OP3型~OP7型、OP4L型~OP7L型、全サイズ)、ジャンボモール、VE管(サイズ14~36)、CD管・PF管(サイズ14~54)、ミラレックス(サイズ22~54)、ミラレックスF(サイズ20~50)、アルミフレーム用部材モール(AFP-EML3)、アルミフレーム用部材配線ダクト(AFP-D3030G)。全長:288mm、重量:640g。', 15600, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-MD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
