INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-BA3', '全ねじカッター (インパクトドライバー用 W3/8ボルト用カッターアタッチメント)', 'お手持ちのインパクトドライバーに手軽に取り付けられる、ボルト切断専用の合体型カッター。重量約2kgと軽いので腕に負担がかからず、取り外した後の持ち運びもラク。グリップハンドルや回り止めアームが取り外せ、小さいサイズになるため、保管に困らない。シンプル構造で替刃の交換が簡単。切断したボルトにそのままナットがねじ込める。18V充電式インパクトドライバー(14.4Vも使用可能)、六角軸シャンク径:6.35mmに対応。W3/8ボルト(SS400,S20C等の軟鉄焼き入れをしていないこと)に対応。重量:約2kg。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-BA3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-BA3H', '全ねじカッター替刃 (切り刃A・受け刃B)', '切り刃A・受け刃B×各1枚入。MC-BA3用。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-BA3H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-CA100', 'ケーブルカッター (インパクトドライバー用 電気配線専用カッターアタッチメント)', 'お手持ちのインパクトドライバーに手軽に取り付けられる、配線切断専用の合体型カッター。重量1.01kgと軽いので腕に負担がかからず、取り外した後の持ち運びもラク。アームが折りたため小さいサイズになるため、保管に困らない。シンプル構造で替刃の交換が簡単。18V充電式インパクトドライバー(14.4Vも使用可能)、六角軸シャンク径:6.35mmに対応。600V-CV100mm²までの単心ケーブル、600V-IV100mm²までの単心ケーブル、Fケーブルも切断可能。重量:約1kg。', 67200, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-CA100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
