INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-CM5', 'ケーブルカッター固定ねじ (交換用)', 'MC-CA100用。', 360, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-CM5', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MC-CA325', 'ケーブルカッター325 (インパクトドライバー用 電気配線専用カッターアタッチメント)', 'お手持ちのインパクトドライバーに取り付けCVケーブル325まで切断できる、電気配線切断専用の合体型カッター。重量約2kgと軽いので腕に負担がかからず、取り外した後の持ち運びもラク。グリップハンドルや回り止めアームが取り外せ、小さいサイズになるため、保管に困らない。18V充電式インパクトドライバー(14.4Vも使用可能)、六角軸シャンク径:6.35mmに対応。600V CVケーブル単心CV325以下、φ31以下のケーブルに対応。重量:約2kg。刃交換はメーカー修理となります。', 120000, 'https://dummyimage.com/200x200/cccccc/000.png&text=MC-CA325', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KRT-22', '管だけカッター', '管だけをきれいに切断。波の山側を切るので管内のケーブルや呼び線を傷つけない。管にはめ込み回すだけで作業スペースをとらず高所や狭い箇所でもラクラク切断可能。刃先に指が触れない安全な構造。PF管・CD管に対応。替刃収納スペースあり。適合管:PF単層波付管(MFS-16-22)、CD管(MFCD-16-22)。', 5190, 'https://dummyimage.com/200x200/cccccc/000.png&text=KRT-22', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 56, 130, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KRT-22H', '管だけカッター替刃', '2枚1組。KRT-22用。', 2370, 'https://dummyimage.com/200x200/cccccc/000.png&text=KRT-22H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SRT-28', 'するっとカッター', '管だけをきれいに半割れにカット。切っ先はカバー付なのでケーブルや呼び線を傷つけない。管にはめ込みスライドさせるだけでコンパクトで高所でもラクに作業可能。刃先に指が触れない安全な構造。替刃も収納可能。適合管:PF管(14、16、22、28) ※MFXも含む、CD管(14、16、22、28)、FEP(20、30)。適合管径:φ19～φ36.5。', 5190, 'https://dummyimage.com/200x200/cccccc/000.png&text=SRT-28', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 55.3, 115, NULL);
