INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-CV1HS', 'トリッパー CV標準セット', 'トリッパーCV、ケーブルピーラー等を収納した樹脂製ハードケース付のセット。耐久性に優れたハードケースなので保管用としても最適。セット内容:トリッパーCV(TOR-CV1M)×1、ケーブルピーラー(TOR-CV8)×1、(TOR-CV14)×1、(TOR-CV22)×1、(TOR-CV100)×1、(TOR-CV150)×1、樹脂製ハードケース(TOR-CV1HC)×1。', 20800, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-CV1HS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 160, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-CV2HS', 'トリッパー CV標準セット (大径用)', 'トリッパーCV、ケーブルピーラー等を収納した樹脂製ハードケース付のセット。耐久性に優れたハードケースなので保管用としても最適。セット内容:トリッパーCV(大径)(TOR-CV2M)×1、ケーブルピーラー(大径)(TOR-CV250)×1、補助ハンドル(TOR-H2)×1、樹脂製ハードケース(大径用)(TOR-CV2HC)×1。', 16500, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-CV2HS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 160, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-CV1HC', 'ハードケース (トリッパーCV1型・EE1型用)', 'トリッパーCV1型(EE1型)×1、ケーブルピーラー×5に対応。', 4180, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-CV1HC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 160, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-CV2HC', 'ハードケース (トリッパーCV(大径)用)', 'トリッパーCV(大径)×1、ケーブルピーラー(大径)×1、補助ハンドル×1に対応。', 4180, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-CV2HC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 160, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-CV1C', 'トリッパー CVケース (布製)', 'トリッパーCV1、トリッパーEE1、ケーブルピーラーが収納できる布製ケース。ベルトに通せるループ付。収納量:トリッパーCV1型・EE1型×1、ケーブルピーラー(替刃)×3。ピーラーホルダー、ピーラーホルダー落下防止ヒモ付(約1m)。', 3480, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-CV1C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-EE1HSE', 'トリッパー EE延長セット', '延長スペーサー付のトリッパー本体と、ケーブルピーラー EE用を収納した樹脂製ハードケース付のセットです。耐久性に優れたハードケースなので保管用としても最適です。ケース内空白の位置に電動アタッチメント(品番:TOR-1D6)を入れることができます。', 21000, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-EE1HSE', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 68, 160);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-1SY', 'ケース本体', 'トリッパー CV (EE)とケーブルピーラー3個が収納できるベルト掛けケースです。ベルトにつけたままケースごと取り外せる着脱式ホルダータイプです。着脱式ホルダーは、前後、左右に首が回転するため、どんな姿勢にでも対応します。ケースは片手で着脱できます。', 5780, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-1SY', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-1F', 'トリッパー・F', 'VVFケーブルを常に理想位置でカット!心線を傷めることなく、表皮の切り取りから、心線の皮むきまで、スピーディーにできます。操作が簡単なスプリング開口式の使い易いデザインです。ロック付で、切刃の保護もバッチリです。確実な切れ味で、切刃の取替えが簡単にできます。(替刃付)本体には寸法目盛りが表示してあり、携帯に便利なクリップ付です。', 2940, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-1F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-1FK', 'トリッパー・FK', '盤回り等、長く被覆をむく場合に使用します。操作が簡単なスプリング開口式の使い易いデザインです。ロック付で、切刃の保護もバッチリです。確実な切れ味で、切刃の取替えが簡単にできます。(替刃付)本体には寸法目盛りが表示してあり、携帯に便利なクリップ付です。', 2940, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-1FK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 131, NULL);
