INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-1FM', 'トリッパー・Fミニ', '携帯に便利なコンパクトタイプのVVFケーブル皮むき器です。IV線の被覆はぎ取り長さの目安(10mm)付。作業のラクなスプリング開口式。切刃の交換も簡単にできます。(替刃をご購入ください。)', 2640, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-1FM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 22, 72);
