INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TOR-1C', 'トリッパー・CX', '同軸ケーブルを常に理想位置でカット!心線・編組線を傷めることなく、スピーディーに皮むきができます。操作が簡単なスプリング開口式の使い易いデザインです。本体にイラスト目盛りと寸法目盛りが表示してありますから、入線長さは一目瞭然です。ロック付で、切刃の保護もバッチリです。確実な切れ味で、切刃の取替えが簡単にできます。(替刃付)携帯に便利なクリップ付です。', 2640, 'https://dummyimage.com/200x200/cccccc/000.png&text=TOR-1C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 54, 30, 117);
