INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DRM-100EI', '電工ドライバー(絶縁キャップ式) マイナス', 'スマートメーターへの取替作業に最適!伸縮する絶縁キャップで金属部を覆っていますから短絡等、作業ミスの防止ができます。すべりにくいゴム製のグリップですから、手にピッタリフィット。グリップ本体はプラスチック製です。絶縁キャップを外しても使用できます。(耐電圧仕様ではありません)ビット呼び寸法: Φ7.2×100(刃幅6mm)。全長: 202mm。グリップ径: Φ42。', 2020, 'https://dummyimage.com/200x200/cccccc/000.png&text=DRM-100EI', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 42, 202, NULL);
