INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SKK-1', 'ソケットくるくる', '電動ドライバーを用い、吊りボルト上のナットを移動させる場合に使用します。', 4580, 'https://dummyimage.com/200x200/cccccc/000.png&text=SKK-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 54, 723, 54);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'NKK2-S', 'ナットくるくる2', '電動ドライバーを用い、吊りボルト上のナットを高速で移動させることができます。市販のソケットに取り付け、電動ドライバーに装着します。ハイスピードでナットが回転。作業能率が大幅にアップできます。ソケット一体型ではないため、交換費用が安価です。ゴム製の独特なヒダ形状により、ナットへの食いつきがよく、スムーズに回せます。', 700, 'https://dummyimage.com/200x200/cccccc/000.png&text=NKK2-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 42, 42, 20);
