INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GG-1', 'ガス式鋲打機 G-Shot', '固定具等を、コンクリート等、硬い対象材へ固定する場合に使用します。作業環境に応じて、打ち込み強さを調整できる調整ガイド。脱着式マガジンのため、鋲詰まりなどの対応が簡単です。コンパクトで長持ちするリチウムイオン電池採用のバッテリーパック。バッテリー残量を赤と緑のLEDランプでお知らせします。', 177000, 'https://dummyimage.com/200x200/cccccc/000.png&text=GG-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 111, 380, 360);
