INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LH-270', 'ラクウチハンマー', 'カナヅチでは打ちにくかった所にも、ラクラクと釘打ちができる新しいハンマーです。カラ打ちがなく、スピーディーに釘打ちができます。すべりにくいゴムの握りです。LH-270は全長わずか270mmのコンパクトサイズながら、グリップが2段階伸びるので、打ち込み威力は抜群です。工具箱にも入ります。', 15500, 'https://dummyimage.com/200x200/cccccc/000.png&text=LH-270', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 270, 196);
