INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BE-A325', 'ケーブルベンダー', '被覆付ケーブルの曲げ、伸ばし作業に使用します。アルミ製なので軽量です。角度目盛り付。製品重量: 454g。適合ケーブル: Φ22~Φ31 (CV150mm²~CV325mm²、単心に相当する太さ)。', 9360, 'https://dummyimage.com/200x200/cccccc/000.png&text=BE-A325', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 473, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-500H', 'インサートハンマー', 'ニューカラーインサート・型枠用専用ハンマー。深いはり底等、カナヅチでは打ちにくかった場所にもラクラク、インサートが打ち込めます。インサートを差し込むだけでOK! 2・3回で簡単に打ち込めます。持ち運びに便利なグリップ抜け防止のストッパーが付いています。適用: ニューカラーインサート、カラー・ヘッダーインサート。※W3/8用(ショートタイプ)には使用できません。', 15800, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-500H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 647, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-1000H', 'インサートハンマー', 'ニューカラーインサート・型枠用専用ハンマー。深いはり底等、カナヅチでは打ちにくかった場所にもラクラク、インサートが打ち込めます。インサートを差し込むだけでOK! 2・3回で簡単に打ち込めます。持ち運びに便利なグリップ抜け防止のストッパーが付いています。適用: カラー・ヘッダーインサート (デッキプレート用・ばねタイプ)。', 22600, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-1000H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 1147, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-RS3', '楽打ちインサートスティック', 'デッキプレートへのインサート取り付けが立ったまま行えるので、作業が速く足腰への負担も軽減されます。スティックにインサートを入れるだけで取り付け準備完了。デッキプレートの穴に差し込みスティックを押し込むだけです。スティックにはインサートを15個装填できます。透明なのでインサートの数や色が確認できます。適用: カラー・ヘッダーインサート (デッキプレート用・ばねタイプ) W3/8用。', 14800, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-RS3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 114, 1100, 84);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-RS3H', '楽打ちインサートスティック 先端部', '楽打ちインサートスティックの交換部品。', 1710, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-RS3H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-1N', 'ボックスアッター', '金属探知器。2個のランプでお知らせする2点探知式ですから埋設物(ボックス・パイプ・鉄骨・鉄筋・釘)等の判別が容易です。金属ならどんなもの(鉄・銅・アルミ・鉛等)でも壁の表面からズバリ正確な位置を探知します。ダイヤル(感度)調整が容易なツマミ式。スライドボックス(日本間ボックス)の切り込みゲージ付です。水平器付。ブザー音の「入切」スイッチ付。電源:単四アルカリ乾電池4本(別売)。連続使用時間:72時間。携帯用ケース付。穴あけセンター出しゲージ付。', 25000, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-1N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 112.5, 145, 25);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-2', 'ボックスアッター 2 センター探知器', '金属探知器。感度の強さが一目でわかる見易い感度ランプ付です。感度ランプのレベルにより、埋設物の中心が手にとる様にわかります。埋設物の深さにより、感度が自在に変えられます。首振り自在、壁面に合わせ使い易い角度に調整できます。電池容量が一目でわかるパワーランプ付です。方向性がない丸い探知面ですから、どんな方向からでも同様に探知できます。探知面センターにけ書きポイントが設けてあります。細い鉄筋(W3/8)等は探知しませんから、埋設物(ボックス・パイプ等)の判別が容易にできます。重量280g(電池含む)。電源:単三乾電池(1.5V)4本付。中心探知能力: 探知物の面積により異なりますが、70~100mmの深さまで中心探知できます。(例: 鉄製アウトレットボックス100mm、金属製パイプ(19)70mm)。探知できるもの: 金属(鉄・銅・アルミ・鉛等)。', 29000, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 146, 65);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-SP', 'マグネットアッター', '高感度タイプ。磁石探知器。見易いマトリクスLEDランプとブザーでスライドボックスの磁石を正確に探知し、その位置で穴あけポイントの印(マーキング)ができます。(印(マーキング)はスタンプと突起による印の2通りができます。)ボックスの切り込み、器具の取り付けに便利な水平器付です。電池を節約。オートパワーオフ機能により約1分半で電源が自動的に切れます。独自の方式により、面倒な感度調整が不要です。胸ポケットに入るコンパクトサイズ。セット内容: マーキングポインタ×1 (せっこうボード用突起付)、スタンプ補充用インク×1、携帯用ケース×1。電源:単4乾電池3本(電池別売)。磁石(N極)探知距離: ~40mm (NBS-6は~30mm)。オートパワーオフ: 約1分半。重量:108g(電池含)。適用: 磁石付スライドボックス、ポイントアッター等。', 48300, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-SP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 52, 55, 28.5);
