INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-SPINKR', 'スタンプ補充用インク (赤)', 'マグネットアッター用スタンプ補充用インク。色: 赤。', 610, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-SPINKR', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-SPR', 'キャップ、クッションセット', 'マグネットアッター用。セット内容: キャップ×1コ、替クッション×4コ。改良前の製品は、クッションの交換ができません。交換修理にて本体をクッションセットが交換できるパーツに取り替えます。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-SPR', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-SP3', 'マグネットアッター (高感度・充電・3点印タイプ)', '磁石探知器。見易いマトリクスLEDランプとブザーでスライドボックスの磁石を正確に探知し、その位置で穴あけポイントの印(マーキング)ができます。3点印(マーキング)なので小判穴ホルソー、SBホルソーどちらでも使用できます。ボックスの切り込み、器具の取り付けに便利な水平器付です。USBケーブルでニッケル水素電池に充電ができます。アルカリ電池での使用も可能です。(乾電池誤充電防止機能搭載)。電池を節約。オートパワーオフ機能により約3分で電源が自動的に切れます。独自の方式により、面倒な感度調整が不要です。胸ポケットに入るコンパクトサイズ。セット内容: 本体×1個、スタンプ用保管キャップ×1個、ニッケル水素電池(単4)×2個、スタンプ補充用インク×1個、USBケーブル×1本 (異常発熱時に電流を停止する温度センサー搭載)、取扱説明書×1冊、携帯用ケース×1個。探知ボックス: 磁石(N極)※磁石位置: ボックスセンター。探知距離:9~40mm (NBS-6は9~30mm)。探知誤差:磁石の中心より5mm以内。電源:単4ニッケル水素充電池又は単4アルカリ電池(充電不可)。充電時間:約3時間。オートパワーオフ機能: 約3分。使用温度:5℃~40℃。保管温度:-10℃~40℃。', 52700, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-SP3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 52, 105, 28.5);
