INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-EG2', 'EGアッター2', '磁石探知器。ホルソーの穴あけポイント(磁石)をマーキングする為の磁石探知器です。磁石付スライドボックス又はポイントアッターを取り付けたスライドボックスの穴あけポイント(磁石)の探知に使用します。器具の取り付けに便利な水平器付です。探知距離(穴あけポイント探知用磁石までの距離): ポイントアッター(~30mm迄)、磁石付スライドボックス(~30mm迄)、スーパーポイントアッター(~40mm迄)、継ぎ足しマグネット(~40mm迄)。', 1550, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-EG2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 92, 46, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-EG3', 'マグアッター', '磁石探知器。壁裏の磁石付ボックスを探知する為の磁石探知器です。磁石付スライドボックス又はポイントアッターを取り付けたスライドボックスの磁石位置を大まかに把握できます。コンパスが磁石特有の動きをしますから、磁石か鉄かの判別ができます。探知距離(磁石までの距離): 磁石付スライドボックス・ポイントアッターの磁石探知距離(~30mm迄)、スーパーポイントアッター及び、継ぎ足しマグネットを取り付けてある場合の磁石探知距離(~40mm迄)。鉄の探知距離(~10mm迄)。', 2450, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-EG3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 92, 46, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-TS', '間柱アッター', '木ビス探知器。磁石で壁裏の柱をマーキング! 壁を固定した鉄製木ビスを磁石で探知し、その磁石でマーキングすることにより、壁紙を傷付けずに柱の位置を割り出せます。探知距離: 2mm迄。', 3240, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-TS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 100, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-EG', 'EGアッター', '磁石探知器。スライドボックス新工法でのEGスライドボックス又はポイントアッターを取り付けたスライドボックスの穴あけポイント(磁石)の探知に使用します。探知距離(磁石までの距離): EGスライドボックス・ポイントアッターの磁石探知距離(~30mm迄)、スーパーポイントアッターを取り付けてある場合の磁石探知距離(~40mm迄)。', 830, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-EG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, NULL, 60);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-TDR', 'ケーブルチェッカー', 'ケーブル診断・測長機。ケーブルの長さ(6000m迄)が簡単操作で測長できます。敷設長やケーブルドラムの残量、撤去ケーブルの長さもボタン1つでわかります。機器を外さず測長可能です。(機器接続、開放、短絡でも測長可能。)0.3~400sq迄の2心以上のメタルケーブルの障害箇所の検出・識別を行えます。モニターに映し出される波形からケーブルの障害箇所までの距離や障害の内容が診断できます。スキャン固定機能を使用すると、波形は保持され綿密に分析することができます。高圧ケーブル・電力線・データ回線・通信線及びCCTVケーブルにも対応しています。重量は350g、筐体はIP54基準に適合した頑丈なABS製で屋外使用に最適です。使用温度:-10℃~50℃(保管時-20℃~70℃)。電源:6V(単三アルカリ電池×4本)。セット内容: 0.5m接続リード線、ソフトケース、ユーザーマニュアル。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-TDR', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 165, 37);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BUT-EGW', 'EGアッターW センター磁石専用', '磁石探知器。小判スライドボックス (SBG)のセンター磁石を探知します。探知後は各ホルソーの軸点(3点)を一発マーキングします。探知距離(磁石までの距離): 小判スライドボックス・ポイントアッターの磁石探知距離(~30mm迄)、スーパーポイントアッターを取り付けてある場合の磁石探知距離(~40mm迄)。', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=BUT-EGW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, 50);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E', 'OKチェッカー (アースチェック付)', '引掛シーリング・埋込ローゼット・コンセント・ランプソケット等の検電が簡単にできます。ブザーとランプにより的確な検電作業が同時にできます。(ブザーで通電チェック、ランプで電圧、極性、アースチェック、漏電ブレーカチェック)。アースチェック、漏電ブレーカチェックができるテスターピン付です。※接地形コンセントの場合は別売のアダプタをご使用ください。全長が860mmありますから、天井等の検電作業にも脚立等を使用することなく、検電作業ができます。本体のヘッド部分が前後に角度調整できますから、壁付コンセント等にも使い易い角度で検電作業ができます。200Vの誤配線確認にも大変役立ちます。配線ダクト用の引掛シーリングを取り付ければ配線ダクトの検電にも使用できます。携帯袋付。規格: 単相100V・200V用。', 16100, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 860, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-ELB', 'OKチェッカー(ELB用) アダプタ', '接地線の接続チェックと漏電ブレーカの動作チェックに使用します。OKチェッカーに取り付ければ、高所箇所のコンセントもラクにチェックできます。適合ELB: 定格感度電流(30mA以下)。', 3660, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-ELB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E-ST', 'OKチェッカー(アースチェック付)用 テスター棒', 'OKチェッカーに接続し、高所箇所等の接地線の接続チェックに使用します。全長: 730mm。リード線長さ: 1000mm。重量: 280g。', 4420, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E-ST', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 730, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E-100', 'OKチェッカー(アースチェック付)用 アダプタ', '接地形コンセント用リード線付(870mm)。OKチェッカーで接地形コンセントのチェックを行う場合に使用します。適合接地形コンセント: 15A-125V、20A-125V共用。', 3660, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E-200', 'OKチェッカー(アースチェック付)用 アダプタ', '接地形コンセント用リード線付(870mm)。OKチェッカーで接地形コンセントのチェックを行う場合に使用します。適合接地形コンセント: 15A-250V、25A-250V共用。', 3660, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E-200', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E-IH', 'OKチェッカー(アースチェック付)用 アダプタ', '接地形コンセント用リード線付(コード長1100mm)。OKチェッカーで接地形コンセントのチェックを行う場合に使用します。IHクッキングヒーターの検電に最適です。コード付ですから、キッチン扉奥のコンセントの検電もラクにできます。適合接地形コンセント: 30A-250V。', 7020, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E-IH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-1E-BCA', 'OKチェッカー(アースチェック付)用 アダプタ', '接地形コンセント用リード線付(コード長1030mm)。OKチェッカーで接地形コンセントのチェックを行う場合に使用します。防水コンセント等の検電に使用します。適合接地形コンセント: 15A-125V。', 4420, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-1E-BCA', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KDK-L', 'OKチェッカー (ライトタイプ)', '引掛シーリング・埋込ローゼット・コンセント・ランプソケット等の通電が電球の点灯により確認できます。全長: 853mm。重量: 470g。添付品: コンセントアダプタ×1、ソケットアダプタ×1。適用: AC100V用、適応電球: 60W以下(口金E26)。', 7100, 'https://dummyimage.com/200x200/cccccc/000.png&text=KDK-L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 853, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LA-1', 'レベルアッター (器具取付枠用水平(垂直)器)', '配線器具を垂直に取り付けるための水平(垂直)器です。携帯ケース付。振り子と目盛りで合わせます。表面(水平)・裏面(垂直)どちらでも使用できます。プレート等の垂直確認も行えます。', 1090, 'https://dummyimage.com/200x200/cccccc/000.png&text=LA-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LG-B', 'ボックスレベルゲージ (LED付)', 'LEDライト付なので、暗い場所でもレベル出し、け書きができます。レベルゲージはLEDライト部と分離できます。(LEDライト単品もあります。)小判穴ホルソー用パネルボックス等の穴あけセンターのけ書きもできます。磁石付なので金属面に取り付けて使用できます。電池: CR1620×2個。', 4620, 'https://dummyimage.com/200x200/cccccc/000.png&text=LG-B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 46, 92, 13);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LGL', 'LEDライト', 'ボックスレベルゲージ用LEDライト。LG-B用。', 1860, 'https://dummyimage.com/200x200/cccccc/000.png&text=LGL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PTL-H1', 'ピタレベ (粘着式水平器)', '横引き配管の水平測定及び排水管の勾配測定に使用します。繰り返しの使用が可能な粘着ゲルにより、樹脂管でもピタッと取り付けられます。粘着力が弱まった場合は、水洗いやウエットティッシュで清掃すれば粘着力が復活します。気泡管は6本ラインですので、勾配1/100、1/50を測定できます。感度:0.35mm/m=0.0201°。精度:±2.5mm/m=±0.1432以内。使用温度:-20℃~45℃。適合管サイズ: 配管径21.7以上 (塩ビ管サイズ16以上・SGP15A以上)。', 3630, 'https://dummyimage.com/200x200/cccccc/000.png&text=PTL-H1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 110, 46.5, 17.3);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KG-CDO', 'ボックス位置ゲージ', '軽量間柱に取り付けるボックスの位置出しを床にけ書くゲージです。コンパスとしても使用でき、ボイド管やスリーブのけ書きができます。適合: 中形四角ボックス、大形四角ボックス。コンパス径: Φ140・Φ190・Φ240。', 1400, 'https://dummyimage.com/200x200/cccccc/000.png&text=KG-CDO', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 85, 160, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AAG-VE', '穴あけゲージ (VE管用)', 'プールボックスに、ミラックハンガーで浮かせたVE管、及び2号コネクタを接続する場合の開口センターを割り出すゲージです。適用: VE管・2号コネクタ。', 1400, 'https://dummyimage.com/200x200/cccccc/000.png&text=AAG-VE', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 100, 150, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RG-250', 'レインボーゲージ', 'ダウンライトの穴あけや、コア抜きの開口径のけ書きに使用します。(Φ75~Φ250までの7サイズの円をけ書くことができます。)1/4サイズに折りたためるため、コンパクトで持ち運びに便利です。適用け書きサイズ: Φ75・Φ100・Φ125・Φ150・Φ175・Φ200・Φ250。', 1620, 'https://dummyimage.com/200x200/cccccc/000.png&text=RG-250', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LGS-KG', 'LGS用け書きゲージ', '軽量間柱にボルト貫通用のパンチ穴をけ書く場合に使用。(穴サイズ: W3/8ボルト)。軽量間柱に軽量間仕切り用調整固定バーを取り付けるためのゲージとしても使用できます。磁石付なので、軽量間柱に仮保持できます。け書き位置は、1㎜単位で調整できます。水平器付です。折りたたんでコンパクトに収納できます。', 3000, 'https://dummyimage.com/200x200/cccccc/000.png&text=LGS-KG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DS-15', 'デンコースケール(電線・パイプ径付 150mm直尺)', '直尺150mmにIV線とVE管(厚鋼電線管・CD管近似)のサイズ目盛りが付きました。JIS1級(ステンレス製シルバー仕上)ですから、強く、長持ちします。胸ポケットに入る手頃な使い易いサイズです。', 760, 'https://dummyimage.com/200x200/cccccc/000.png&text=DS-15', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 175, 15, 0.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KG-SB1', 'け書きゲージ(スライドボックス用)', '様々なけ書きに対応できるマルチけ書きゲージです。着脱可能な水平器付。', 5300, 'https://dummyimage.com/200x200/cccccc/000.png&text=KG-SB1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KG-SB2', 'け書きゲージ(スライドボックス機器用)', 'スライドボックス(機器用)を開口するためのゲージです。ホルソー(Φ29)での穴あけにも対応しています。水平器付です。', 2400, 'https://dummyimage.com/200x200/cccccc/000.png&text=KG-SB2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 26, 158, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KG-SB3', 'け書きゲージ(コンパス付)', 'スライドボックス、パネルボックスのけ書きに加え、コンパスとして円もけ書けるゲージです。2ヶ用以上のボックスもけ書けます。金属下地や木ビスも探知できる磁石付きです。水平器付です。', 3400, 'https://dummyimage.com/200x200/cccccc/000.png&text=KG-SB3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 70, 120, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WAC-3', 'ワッシャーキャッチ®', '吊りボルトに固定してある器具を取り外す際に、ワッシャー等の落下を軽減する工具です。ワッシャーキャッチの上部に磁石が付いており、ワッシャーをキャッチします。充電ドライバー等のソケットに簡単に取り付けられます。', 700, 'https://dummyimage.com/200x200/cccccc/000.png&text=WAC-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 32, 14, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MKH-16', 'マグネットキャッチ', 'デッキプレートインサートの穴開け時に出る、切粉の回収に使用する磁石です。持ち運びに便利なサイズです。六角レンチ付ハンマー(対角21~22.2mm)に取り付けることもできます。VE管に取り付ければ、かがむことなく切粉の回収作業が行えます。また、マグネット部にインサートを吸着すれば、インサートの取り付け作業も立ったまま行えます。', 1710, 'https://dummyimage.com/200x200/cccccc/000.png&text=MKH-16', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 39, 61, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SBG-S', '小判穴ホルソーS (強化せっこうボード、せっこうボード専用)', '穴あけ作業大幅短縮! ボックスの穴あけが一発でできる小判穴タイプのホルソーです。削り調整不要!配線器具がそのまま取り付けられます。(開口穴径:タテ102×ヨコ54~56mm)。柱・壁際に寄って穴あけができます。(13.6mm迄OK)。お手持ちの充電ドライバーに取り付けるだけでOK! (14.4V推奨)。水平器付で真直ぐ穴あけができます。', 33000, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SBG-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 286, NULL);
