INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SBGP2B', '小判穴ホルソー(セミハードケース付)', '穴あけ作業大幅短縮! ボックスの穴あけが一発でできる小判穴タイプのホルソーです。グリップ付なのでしっかり保持できます。削り調整不要!配線器具がそのまま取り付けられます。柱・壁際に寄って穴あけができます。(13.6mm迄OK)。お手持ちの充電ドライバーに取り付けるだけでOK!(14.4V推奨)。水平器付きで真直ぐ穴あけができます。丈夫なセミハードケース付。', 45800, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SBGP2B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 151, 90, 286);
