INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SDS', 'SDSシャンクビットアダプター(小判穴ホルソー用)', '小判穴ホルソーを大容量の充電式ドリルドライバーにセットする場合に使用します。', 3640, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SDS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 17, 70, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SB60', 'SBホルソーEG', 'ボックス穴をホルソーであけるEG工法に使用し、せっこうボード(強化、硬質を含む)、合板・ケイカル板の穴あけに最適な、Φ60専用SBホルソーです。(刃の着脱・交換はできません。)透明カバーがない分、柱・壁際に寄って穴あけができます。(8mm迄OK)。SBホルソー同様、お手持ちの電動ドリルに取り付けるだけでOK!', 3340, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SB60', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 121.5, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SBP56', 'SBPホルソー®', 'せっこうボード(強化・硬質を含む)にボックス穴をホルソーであける工法に最適な、Φ56専用SBPホルソーです。(刃の着脱・交換はできません。)透明カバーがない分、柱・壁際に穴あけができます。(5mm迄OK)。お手持ちの電動ドリルに取り付けるだけでOK!', 4420, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SBP56', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 56, 105, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DH-63', 'デンコーホルソー®', '1本で7サイズの穴があけられるおトクなホルソーです。刃の着脱はワンタッチ!', 3740, 'https://dummyimage.com/200x200/cccccc/000.png&text=DH-63', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 69, 109, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SB', 'SBホルソー', 'ボックス穴をホルソーであけるEG工法に使用し、せっこうボード(強化、硬質を含む)、合板・ケイカル板の穴あけに最適です。お手持ちの電動ドリルに取り付けるだけでOK!丈夫な透明カバー付ですから、切粉の散飛が防止できます。また、カバー蓋が取外せ、切粉の排除がカンタンにできます。センターシャフトが伸縮し、壁厚に合わせて切削深さが調整できますから、壁内のボックス等を傷つけず穴あけができます。新形状の刃を使用し、後処理のいらないきれいな穴あけができます。(替刃式)。柱等(凸部20mm迄)の際に穴あけができるようにカバーアダプタがつきました。', 24400, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 119, 241, NULL);
