INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-SB3', 'SBホルソー用センターガイド', 'SBホルソー使用時に、1つ目の穴の開口がズレた時や、既に大工さんによって穴があけられている箇所等、SBホルソーのセンターがとれない場合に使用します。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-SB3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
