INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-150', 'フリーホルソー® (せっこうボード・合板用)', 'ダウンライトの穴あけ等、天井材(せっこうボード・合板)等の穴あけに最適です。(FH-350はせっこうボード専用です。)お手持ちの電動ドリルに取り付けるだけでOK!FH-150、200Nは寸法調整が簡単にできる、両刃同時調整式です。丈夫な透明カバーと防塵クッション付ですから、切粉の飛び散りを防げます。板厚に合わせて切削深さが調整できますから壁内のものを傷つけません。防塵クッションは取替え可能。FH-150、200Nはカバーの取り外しができます。(掃除が簡単にできます。)', 26900, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 204, NULL, NULL);
