INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-125F', 'フリーホルソー®(深型) (せっこうボード専用)', 'ダウンライトの穴あけ等、天井材(せっこうボード)の穴あけに最適です。小型軽量で取り回しがしやすく、カバー外形が小さいので隅角の作業もラクに行えます。深さ調整にロック機構が付いているので作業中に目盛りがズレることがありません。壁面開口作業時の切粉の落下を防止し、収集できるダストカバー付。', 31900, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-125F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 183, NULL, NULL);
