INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-3H', '平削りブレード', 'ロックウール吸音板の穴あけをしながら山落しが行える便利なアタッチメントです。B寸法調節:8~28mm。ロックウール吸音板用(FH-250、(~$250迄))。', 1140, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-3H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-UP', 'パイアップの治具', '一度あけたダウンライトの穴を大きくしたい場合に使用します。フリーホルソー用。取り付け穴径に合わせ5サイズのプレートで切り替えます。FH-125Fには使用できません。', 4180, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-UP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-C125F', 'ダストカバー', 'フリーホルソーでの壁面開口作業時の、切粉の落下を防止し、収集します。適合フリーホルソー: FH-125F-125FH・125FB用。切込み深さがラバータイプより3~4mm深くなります。下地材の干渉にご注意ください。', 1210, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-C125F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-C150', 'ダストカバー', 'フリーホルソーでの壁面開口作業時の、切粉の落下を防止し、収集します。適合フリーホルソー: FH-150用。切込み深さがラバータイプより3~4mm深くなります。下地材の干渉にご注意ください。', 1260, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-C150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
