INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CCD-22M', '断熱材ドリハ', '断熱材(発泡ポリスチレン・ウレタンフォーム等)へのPF管(22迄)配管用の溝切り加工が簡単にできる、回転用ドリルビットです。ガラス繊維入りプラスチック製。規格:切削径・溝幅(約30)、切削深さ(25mm迄)、シャンク径(φ9)。電動ドリル推奨回転数(2000R.P.M以上)。', 150, 'https://dummyimage.com/200x200/cccccc/000.png&text=CCD-22M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KUG-F', 'F・ころ用釘抜き工具', '天井から突出したF・ころエンド、インサート等の釘を、簡単に抜くことができます。挟んだ釘を、てこの要領で1回で簡単に抜けます。適合:F・ころエンド等(スクリュー釘付タイプ) ※商品底面の幅が60mm以下。', 11700, 'https://dummyimage.com/200x200/cccccc/000.png&text=KUG-F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 219, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MS-13D', 'デッキドリルビット', 'デッキプレートへの穴あけ(φ13)にご使用ください。シャンク径φ9.5ですから、小型電動ドリルでOK! シャンクはスリップを防止するV溝付です。電動ドリルのチャック爪を保護する、保護リング付です。規格:ドリル径(φ13)、シャンク径(φ9.5)、全長(124mm)、刃長(65mm)。', 9040, 'https://dummyimage.com/200x200/cccccc/000.png&text=MS-13D', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 124, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVH-60', '塩ビホルソー', '7サイズの穴あけができる。刃は摩擦抵抗の少ない丸棒状です。もちろん取り替えもできます。本体内にセットしたスプリングにより一定の力で切削でき、きれいな穴あけができます。VE70、VE82のノックアウト径に対応! 硬質塩ビ板:厚さ8mm迄、シャンク径:φ8、センタードリル径:φ4。切削径(呼び):Φ22(16), Φ34(28), Φ48(42), Φ60(54), Φ27(22), Φ42(36), Φ54。', 14800, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVH-60', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 86, 131, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'PVH-89', '塩ビホルソー', '12サイズの穴あけができる。刃は摩擦抵抗の少ない丸棒状です。もちろん取り替えもできます。本体内にセットしたスプリングにより一定の力で切削でき、きれいな穴あけができます。VE70、VE82のノックアウト径に対応! 硬質塩ビ板:厚さ8mm迄、シャンク径:φ8、センタードリル径:φ4。切削径(呼び):Φ22(16), Φ34(28), Φ48(42), Φ60(54), Φ70, Φ82, Φ27(22), Φ42(36), Φ54, Φ65, Φ76(70), Φ89(82)。', 17300, 'https://dummyimage.com/200x200/cccccc/000.png&text=PVH-89', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 113, 131, NULL);
