INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FH-100SL', '交換式ホルソー', '硬質せっこうボード、ケイカル板、合板、サイディング(窯業系のみ)等の固いボードの穴あけに最適です。表面に起伏や目地がある場合でも安全に開口できます。お手持ちの電動ドリルに取り付けるだけでOK! 刃は工具を使わずワンタッチで着脱が可能です。丈夫な透明カバー付ですから、切粉の散飛が防止できます。深さ目盛りで下地材との干渉を低減できます。切削径(100)。切削深さ:せっこうボード25mm迄、合板・ケイカル板12mm迄、サイディング(窯業系のみ)21mm迄。シャンク径(10)。ハードケース付。', 79600, 'https://dummyimage.com/200x200/cccccc/000.png&text=FH-100SL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 119, 137.5, 237.5);
