INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DHC-70', 'ダストカバー', 'ホルソーによるエアコン冷媒管の穴あけの際、切粉飛散を防止し、収集します。ホルソー径φ70迄。粘着テープ付。', 1050, 'https://dummyimage.com/200x200/cccccc/000.png&text=DHC-70', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 77, NULL, NULL);
