INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDH-70C', 'ホルソー用切粉カップ', 'ホルソーでの壁面開口作業時の切粉の飛散、落下を防止し収集します。外径70mm迄のホルソーに対応します。(シャンク径は10mm迄)。ドリルにも使用できます。適合:最大径70mm迄のホルソー、SBホルソーEG (FH-SB60)、SBPホルソー (FH-SBP56)、デンコーホルソー (DH-63)。', 820, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDH-70C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 94, 121, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CCA-C', '切粉カップ', 'ホルソーでの壁面開口作業時の切粉の飛散、落下を防止し収集します。外径140mm迄のホルソーに対応します。(シャンク径は12mm迄)。適合:最大径140mm迄のホルソー。', 2880, 'https://dummyimage.com/200x200/cccccc/000.png&text=CCA-C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 190, 220, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DFC-V', '粉塵カップ', '掃除機と連結し、ドリルでの穴あけ作業時の粉塵収集を行います。蓋が透明なので穴あけ位置が確認できます。ドリル挿入穴径:Φ20。取り付けホース適合内径:約28~40。', 2520, 'https://dummyimage.com/200x200/cccccc/000.png&text=DFC-V', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 30, 43.5, 236.3);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'HDFC-V', '粉塵カップ', '掃除機と連結し、ドリルでの穴あけ作業時の粉塵収集を行います。蓋が透明なので穴あけ位置が確認できます。兼用タイプは外径70迄かつ115mm迄のホルソーに対応します。(シャンク径は20迄)。取り付けホース適合内径:約28~40。適合:最大径70迄のホルソー(せっこうボードのみ)、SBホルソーEG (FH-SB60)、SBPホルソー (FH-SBP56)、デンコーホルソー (DH-63)。', 3680, 'https://dummyimage.com/200x200/cccccc/000.png&text=HDFC-V', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 93.6, 131, 196.7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FDH-UC', '切粉カップ', 'ドリルでの金属盤穴あけ作業時の切粉落下を防止し収集します。磁石付なので仮固定ができ、位置決めがラクに行えます。折りたたみ式でコンパクトです。シリコーンゴム製ホルダーは取り外して水洗い可能です。ホルダーは高い耐熱性能を有しております。適合開口径:～φ35迄。', 2840, 'https://dummyimage.com/200x200/cccccc/000.png&text=FDH-UC', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 77.5, 30, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-9C', 'デンコーキャリーボックス', '携帯・保管用の収納ケースと識別・整理用の小物ケース9個をセットしました。9個の小物ケースが片手でラクラク運べます。小物ケースは収納ケースにロックされ、逆さにしても落ちません。収納ケースにはベルト、ヒモ通し穴が設けてあります。デンコーキャリーボックスは積み重ねて保管することができます。小物ケースは収納物が見える半透明を3色(白、青、緑)揃えました。小物ケースの蓋は開閉ロック式。収納スペースには取り外しができる中仕切りが付いています。小物ケース蓋の裏に釘、ビス等の仮保持ができる磁石が付いています。小物ケースには幅50mm迄のベルトに取り付けられるベルト掛け用フックが付いています。セット内容:収納ケース×1、小物ケース(白)×3、小物ケース(青)×3、小物ケース(緑)×3。', 4380, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-9C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 282, 300, 63);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-W', '小物ケース (白)', 'デンコーキャリーボックス用小物ケース。白(半透明)。', 420, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 92, 79, 61);
