INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-1', 'デンコーボックス (黄)', 'ビス・釘・スリーブ等の小物がスッキリ収納できます。区分けされたビス・釘等が混ざることなく、ボックスを傾けても収納物はこぼれません。ベルト掛けができ、蓋のストッパーにより、蓋が自然に開いたりしません。透明蓋タイプは収納物の量や種類が一目で確認できます。軽いプラスチック製(重量:240g)。適用:ビス・釘・スリーブ等の小物入れに。', 1980, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 140, 90, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-1C', 'デンコーボックス (透明蓋タイプ)', 'ビス・釘・スリーブ等の小物がスッキリ収納できます。区分けされたビス・釘等が混ざることなく、ボックスを傾けても収納物はこぼれません。ベルト掛けができ、蓋のストッパーにより、蓋が自然に開いたりしません。透明蓋タイプは収納物の量や種類が一目で確認できます。軽いプラスチック製(重量:240g)。適用:ビス・釘・スリーブ等の小物入れに。', 1980, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-1C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 140, 90, 68);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-HD', 'デンコーボックスホルダー', 'デンコーボックスを4個セットできる取手付ホルダーです。デンコーボックスが外れないロック機構付。ヒモ通し穴が設けてあり、肩に掛けることもできます。適用:デンコーボックス(DB-1、DB-1C)。', 2540, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-HD', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 190, 107);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-HD4C', 'デンコーボックス付ホルダー', 'デンコーボックス(DB-1C)×4個。', 9360, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-HD4C', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 190, 107);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DB-11', 'パーツボックス', 'ビス・釘・スリーブ等の小物収納箱です。仕切板のはめ替えにより、スペースが自在に変えられます。収納物が見易い透明蓋です。蓋:透明、本体:ベージュ色。プラスチック製仕切板(6枚)付。', 1300, 'https://dummyimage.com/200x200/cccccc/000.png&text=DB-11', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 120, 45, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BS-HJK', '番線ホルダー', '番線、針金、銅線、結束線等の巻物用収納ホルダーです。ホルダーが可動することにより、色々なサイズの巻径に対応でき、キレイに管理することができます。持ち運びに便利な、ベルト通し用フックが付いています。巻物先端部が判らなくなるのを防ぐ為、表側と裏側の両方に先端部の仮止めを設けています。携帯用ベルトフック付(適合ベルト幅:64mm迄)。先端部仮止め付。適合巻径:120~245。最小収納範囲:内寸φ120、外寸φ165。最大収納範囲:内寸φ185、外寸φ245。最大線束径:約30mm。', 3480, 'https://dummyimage.com/200x200/cccccc/000.png&text=BS-HJK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MLZ-1', 'モールケース', 'プラモール・デンコープロテクタ等の小分け、持ち運びに便利です。軽く、丈夫なプラ段(プラスチック段ボール)製です。仕切り板付です。ケースの中身が確認できる透明小窓付です。モールと付属品が分けて入れられる仕切板付。(中仕切りは取り外し可能)。適用(参考入数):プラモール0号(約70本)~4号(約12本)、デンコープロテクタ1号(約50本)~5号(約13本)。', 4920, 'https://dummyimage.com/200x200/cccccc/000.png&text=MLZ-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 115, 1030);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MLZ-2', 'モールケース', 'プラモール・デンコープロテクタ等の小分け、持ち運びに便利です。軽く、丈夫なプラ段(プラスチック段ボール)製です。仕切り板付です。ケースの中身が確認できる透明小窓付です。モールと付属品が分けて入れられる仕切板付。(中仕切りは取り外し可能)。適用(参考入数):プラモール0号(約98本)~5号(約12本)、デンコープロテクタ1号(約70本)~特5号(約10本)。', 8180, 'https://dummyimage.com/200x200/cccccc/000.png&text=MLZ-2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 220, 110, 1040);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MLZ-3', 'モールケース (ソフトタイプ)', 'プラモール・デンコープロテクタ等の小分け、持ち運びに便利です。モール等にキズが付きにくいクッション素材です。収納量が多くても持ち運びラクな肩掛けベルト付。中仕切りは面ファスナーで固定でき、付属品等のサイズに応じて変更できます。また、小物が収納できる小袋付です。適用(参考入数):プラモール0号(約98本)~5号(約12本)、デンコープロテクタ1号(約70本)~特5号(約10本)。', 13900, 'https://dummyimage.com/200x200/cccccc/000.png&text=MLZ-3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 340, 120, 1010);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DSD-1', 'デンコーショルダー', 'パイプベンダーなど長物を収納できる丈夫なセミハードケースです。両手がフリーになり、一度に多くの荷物が運べる肩掛け付のリュックタイプ。側面にネームカードを入れられる窓ポケット付き。パイプベンダー×3本(足踏み型×2本・ヒッキー型×1本)収納可能。名刺サイズのカードが入るカードホルダー付き。小物収納ポケット。適用:全長1280mm以下、重量10kg以下の長物。', 37800, 'https://dummyimage.com/200x200/cccccc/000.png&text=DSD-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 170, 134, 1310);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BWZ-1', '引き出すぞう', 'ドレンホースの長期使用に最適なプラ段ケースです。輸送時の箱のつぶれを防止します。ドレンホースの箱のまま入れるだけ。滑り止めシート付! ケースを屋根等に置いたときに滑り落ちるのを防止します。樹脂製。ドレンホース引出口。適合(ドレンホース):BWH-14型、BWH-16型。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=BWZ-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 420, 440, 240);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RDS-1', '楽だしスタンド', 'PF管・CD管の引き出しが1人でラクにできる配管用スタンドです。管がねじれずスムーズに引き出せます。(管が最後まで崩れません。)縦置きですからスペースをとりません。コンパクトな折りたたみ式! 面倒な組み立ても不要です。軽量(4.5kg)で持ち運びがラクです。ビニールカバー付。寸切りボルトをスタンド脚に取り付け、鉄筋に載せられます。適用:PF管・CD管(サイズ14~28)。使用可能な管寸法:約630mm迄。', 43300, 'https://dummyimage.com/200x200/cccccc/000.png&text=RDS-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 545, 1061, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSSP', '空気スースーパイプ', '腰に差し込むだけ! ファン付作業服の風を作業ズボンに送り込めます。工事店様のアイデアでできた商品です。猛暑対策に。作業ズボンの腰の位置に差し込み、ファン付作業服を被せます。※タイト(スリム)な作業ズボンには効果がありません。', 1700, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSSP', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 175, 139, 45);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'RDS-1S', '楽だしスタンド(ミニ)', 'ケーブル等の引き出しがラクに行える配線用スタンドです。コンパクトな折りたたみ式。重量:2.8kg。使用可能な寸法:外径φ800迄、幅407mm迄。', 32800, 'https://dummyimage.com/200x200/cccccc/000.png&text=RDS-1S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 606, 560, 395);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FEPR-1', 'FEPリール', 'カクフレキ・ミラレックス・ミラレックスF用のターンテーブルです。アームの長さは、2段階に調整できます。コンパクトに分解でき、保管時にスペースをとりません。溶融亜鉛めっき。保管時コンパクトに納まります。適合:カクフレキ・ミラレックス・ミラレックスF。重量:40kg。', 164200, 'https://dummyimage.com/200x200/cccccc/000.png&text=FEPR-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1280, 960, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'USH-1YW', 'USメット (白)', '厚生労働省規格適合品。オリジナルデザインが楽しめる、デザインシール (5枚セット)付です。素早く、確実なサイズ調整が可能なEGヘッドバンド付の内装と安全重視の二重バンドで頭部にジャストフィット!疲労感を少なくしました。画期的なアゴヒモ取り付け方式により安全性をアップ。内装の取り付けが簡単に素早くできます。強いABS製、天面をキレイに仕上げました。ツバの先まで水受けを伸ばした親切設計。斬新で飽きのこないスマートなスタイル。飛来落下・耐電用。使用電圧7000V以下。新感覚の洒落たカラー5色が揃ってあります。頭囲のめやす(555~610mm)。重量:345g。', 5120, 'https://dummyimage.com/200x200/cccccc/000.png&text=USH-1YW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
