INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KPT-VAL', 'VAライナー®', '油性ペン4色付 適合VVFケーブル:1.6×2C・3C, 2.0×2C・3C', 3240, 'https://dummyimage.com/200x200/cccccc/000.png&text=KPT-VAL', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-GSP2', 'ムシハイレンジャー®G(スプレータイプ)', '不快な害虫の通り道になりそうな場所、または棲み付いて欲しくない場所に噴霧できるスプレータイプの忌避剤です。自然乾燥で速やかに乾燥します。(指蝕硬化時間約10分)忌避効果が長く持続します。粘度が低いので、コーティングに適しています。2ウェイノズルの採用で、狭い場所にも噴霧処理ができます。内容量 300ml。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-GSP2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-GPN', 'ムシハイレンジャー®G(ペンタイプ)', '不快な害虫の通り道になりそうな場所、または棲み付いて欲しくない場所に手軽に塗ることができるペンタイプの忌避剤です。コンセントボックス内や壁裏、モールの配管内等に塗って使用します。VOC規制に配慮した、アルコール系インキを使用しています。塗工色は黄色なので、塗りムラ、塗り具合の目安になります。極太で大容量、1本でPETフィルムなら3.6m²以上塗工できます。プラスチック・紙・ゴム・金属等色々な材質に塗工できます。キャップをするだけで、保管も簡単です。マーカーが届かない場所にはフィルム等に塗って、切り取って貼って使えます。アルコール系インキ(油性・速乾・耐水性)。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-GPN', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-GT4010', 'ムシハイレンジャー®G(テープタイプ)', '不快な害虫の通り道になりそうな場所、または棲み付いて欲しくない場所に簡単に切って貼ることができるテープタイプの忌避剤です。プールボックス、ウオルボックス、配電盤内等や、モールの中、壁裏等に貼り付けて使用します。好きな分だけ切って使えます。忌避効果が長く続きます。便利な引き出し口付。幅40mm、長さ10m巻。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-GT4010', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 40, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SS1030', 'ムシハイレンジャー®S(シートタイプ)', '基礎貫通する電気配線用配管材に巻き、配管材とコンクリートの隙間や電線管内からのシロアリの侵入を防ぎます。管に巻きつけるだけの簡単施工。また、ハサミやカッター等で簡単に切断することが可能です。ケーブルと電線管の間に詰め込めば、電線管内からの侵入も防止できます。サイズ:30×10cm。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SS1030', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 100, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SF', 'ムシハイレンジャー®S(不織布タイプ)', 'ケーブルと電線管の間に詰め込めば、電線管内からの侵入を防止できます。ケーブルの屋内引き込み口に巻くことでケーブルを伝ってくるシロアリの侵入も防ぎます。ハサミやカッター等で簡単に加工することが可能です。ムシハイレンジャーS(不織布タイプ)のズレ防止には別売の不織布用両面テープ(品番:MMH-SFT)が便利です。サイズ:30×20cm。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 200, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SFN', 'ムシハイレンジャー®S(不織布タイプ) 難燃性', 'ケーブルと電線管の間に詰め込めば、電線管内からの侵入を防止できます。ケーブルの屋内引き込み口に巻くことでケーブルを伝ってくるシロアリの侵入も防ぎます。ハサミやカッター等で簡単に加工することが可能です。ムシハイレンジャーS(不織布タイプ)のズレ防止には別売の不織布用両面テープ(品番:MMH-SFT)が便利です。UL94のHB相当の難燃性です。サイズ:30×20cm。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SFN', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 200, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SFT', 'ムシハイレンジャー®S(不織布タイプ) 両面テープ', 'ムシハイレンジャーS(不織布タイプ)のズレ防止に便利な両面テープ。サイズ:30×19cm。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SFT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 190, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'FEP-30L-MHS', 'ミラレックス®F(防ギ仕様)', '電線管の内外部どちらをシロアリが歩いても防ギ効果を発揮するFEP管です。防ギケーブルを使う必要がありません。従来FEP管の豊富な付属品がそのままご使用いただけます。1m・5m毎にポイントマーカー入です。外径41mm、近似内径30mm、最大長さ50m。', 1060, 'https://dummyimage.com/200x200/cccccc/000.png&text=FEP-30L-MHS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 41, 41, NULL);
