INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SVP32', 'ムシハイレンジャー®S(水抜き穴パッキン)', 'ハンドホール底面の下穴からのシロアリの侵入を防止します。セット内容:パッキン×1、ブチルテープ×1、スリーブ×1、コンクリートビス×3。適合下穴径:φ32。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SVP32', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 68, 68, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SSC320', 'ムシハイレンジャー®S(防ギシーリング)', '防ギ剤入りのシリコーンコーキングです。ハンドホールへの配管接続作業時の隙間の養生等に使用します。既存のハンドホールの内側からの養生にもご使用いただけます。配管とカップリング等の接続部の隙間埋めにも最適です。耐久性、耐候性、耐水性、電気絶縁性も良好です。硬化時の体積収縮はほとんどありません。-30℃~90℃で使用可能です。容量:320ml。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SSC320', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SP1', 'ムシハイレンジャー®S(パッキン)', '組立式のコンクリート製ハンドホールの接合部分からのシロアリの侵入を防ぐ為に使用する防水防ギパッキンです。その他ハンドホールへのマンホール蓋取り付け用パッキンとしてもご使用いただけます。容量:6m。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SP1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-ST2020', 'ムシハイレンジャー®S(ブチルテープ)', '組立式のコンクリート製ハンドホールとマンホール蓋枠の接合部分等からのシロアリの侵入を防ぐ為に使用する防ギブチルテープです。その他ケーブル貫通部の隙間埋め等にもご使用いただけます。仕様:20mm×3mm×10m。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-ST2020', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 20, 3, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SP2', 'ムシハイレンジャー®S(パッキン用プライマー)', '別売のムシハイレンジャーS(パッキン)(ブチルテープ)をコンクリート面に取り付ける際のプライマーです。容量:1000ml。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SP2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-SPT200', 'ムシハイレンジャー®S(防ギパテ)', '防ギ剤入の不乾性パテです。耐水性で地中管路へのシロアリの侵入防止に最適です。基礎の隙間やハンドホール継枠の隙間、配管取付用開口穴の養生にも最適です。粘土状なので自由に形状を成形・充填できます。容量:200g。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-SPT200', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
