INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NS1030', 'ムシハイレンジャー®N(ブチルシート)', 'ネズミが嫌がる辛み成分を含んだブチルシートです。対象物に巻きつけるだけの簡単施工。ハサミやカッター等で簡単に切断可能です。1袋(5枚入)。サイズ:30×10cm, 10袋入, 最小入数:1袋', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NS1030', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, 100, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NT5010', 'ムシハイレンジャー®N(自己融着テープ)', '忌避効果のある薬剤によってネズミの咬害を低減する自己融着テープです。忌避効果のあるテープとないテープの2層構造になっており、表面側には薬剤が付いていないので施工後の取り扱いも安心です。サイズ:50mm×1m, 入数:1', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NT5010', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 50, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NST3020', 'ムシハイレンジャー®N(シートタイプ)', 'ネズミが嫌がる辛み成分を含んだ軟質塩ビ製のシートです。壁の貫通穴等の経路を塞ぐのに最適です。ハサミやカッター等で簡単に切断可能です。幅:30cm, 長さ:2m, 入数:1', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NST3020', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 300, NULL, NULL);
