INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NMS115P', 'ムシハイレンジャー®N(パンチングシート) パンチ穴付', 'ネズミが嫌がる辛み成分を含んだ軟質塩ビ製シートです。ラック上のケーブル等へのネズミの咬害を防止します。取り外しができるので点検や配線変更も簡単で何度も再利用が可能です。パンチ穴付は放熱対策品です。W:115mm, 適合ミラメッシュ:SRM6-10(D,S,K), 適合ケーブル径:φ20以下, 入数:1', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NMS115P', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 115, NULL, NULL);
