INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NSBH', '盤用配線孔保護材 パテいらず®(防ソ仕様)', '金属製キャビネット上部のケーブル配線孔をパテの代わりに塞ぎ、ネズミやホコリの侵入を防止します。ネズミが嫌がる辛み成分を含んだ軟質塩ビ製シートです。ケーブル貫通箇所を覆ってしまうので隙間が大きい場合にも簡単に施工可能で、パテのような脱落の心配もありません。シート底面の磁石で金属製キャビネットに簡単に施工できます。取り外しができるので点検や配線変更も簡単で、何度も再利用が可能です。適用:屋内用金属製キャビネット等, 入数:1', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NSBH', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 925, 200, 35);
