INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MMH-NP1K', 'ムシハイレンジャー®N(パテタイプ)', 'ネズミが通り抜けそうな隙間等に詰めて使用する防ソパテです。難燃性、不乾性で優れた密着性を有し、安全性にも優れ、長期間安定した防ソ効果を発揮します。パテタイプなので手軽に扱うことができます。難燃性・不乾性。ビニール手袋付。内容量:1kg, 入数:10, 最小入数:1', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MMH-NP1K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
