INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRPD-N', '給電ポール・D用 根かせ', '給電ポール・Dのショートタイプを土中埋設する場合に使用する補強金具です。ボルト・ワッシャー・ナット付。適合:MRPDS-1(K), 入数:1', 10100, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRPD-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 350, 350, NULL);
