INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRP-F', '給電ポール用 ケーブルフック', '充電ケーブル用のフックです。フックは、未使用時にスプリングによって自動的に収納され邪魔になりません。ケーブルと緩衝しやすい部分をゴムで覆っているため、ケーブルを傷めません。添付のねじ3本で表面から簡単に取り付けできます。', 4360, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRP-F', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, 90.4);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRP-H', '給電ポール用 CCIDホルダー', 'EV・PHV用充電ケーブルのCCID用ホルダーです。本体はゴムで覆っており、CCIDケーブルを傷めません。添付のねじ3本で表面から簡単に取り付けできます。適合CCIDサイズ: 幅102mm、奥行き59.5mm以下。', 9900, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRP-H', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 102, 113, 76.5);
