INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBEV-2HSM', 'EVウオルボックス', 'ミルキーホワイト。EV充電ガンやEVコンセント等が収納できる自宅でのEV充電に最適なウオルボックスです。配線スペーサー付は配線の厚みを浮かせられる為、器具が容易に取り付けられます。常設に適したスッキリデザイン!風雨に強いIP44性能!お手軽な金額で、EV充電器周りがスッキリ。コンセント等がむき出しにならないので防犯や安全性が高まります。大掛かりな装置やボックスの取り付けが難しい箇所に最適です。蓋が半開きの状態で保持できるので、降雨時のケーブル等の引き出しに便利です。プラスチック基台。バンド通し穴:裏面(幅11mm)。ノック径:下部:φ27×2、φ21×1、背面:φ31×1、φ22×4。', 4650, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBEV-2HSM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 171, 282, 142);
