INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBV-2M', 'ウオルボックス (プラスチック製防雨ボックス)', 'ミルキーホワイト。3P 60AF×1。常設に適したスッキリデザインに加え、工事現場での使い勝手にもこだわった親切設計!風雨に強いIP44性能!フタを少し開けた状態での保持が可能なので、降雨時の現場やEV・PHVの充電に便利です。(IPX3相当)WBV-2型とWBV-12型及びWBV-3型とWBV-13型は、タテとフカサ寸法が同じで、横に並べた時の仕上りがキレイです。機器取付部にノック穴を備え、壁面への取り付け時の仕上りがキレイです。(木板ベース仕様は除く。)プラスチック基台。', 3120, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBV-2M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 171, 282, 142);
