INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SWP-1', '簡易防水カバー', 'キッチン周りのコンセントへの水はねからの保護、日常使用しないコンセントからの隙間風の軽減やホコリの付着防止に使用します。貼るだけの簡単取り付け!粘着ゲルを使用していますので、繰り返し貼り付けられます。', 420, 'https://dummyimage.com/200x200/cccccc/000.png&text=SWP-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 110, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-S1', 'サイドボックス', '木板。既設の住宅用分電盤への追加や組み合わせに使用します。深夜電力ブレーカー、漏電ブレーカー、ブザー、24時間タイマー等の取り付けに最適です。フレームサイズにこだわらない木板タイプと金属製底板タイプがあります。美しく仕上がる化粧シート付です。底板を取り外して、DINレールがタテヨコ両方向に取り付けられます。', 2990, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-S1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 160, 310, 80.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-ST1', 'サイドボックス', '金属製底板。既設の住宅用分電盤への追加や組み合わせに使用します。深夜電力ブレーカー、漏電ブレーカー、ブザー、24時間タイマー等の取り付けに最適です。フレームサイズにこだわらない木板タイプと金属製底板タイプがあります。美しく仕上がる化粧シート付です。底板を取り外して、DINレールがタテヨコ両方向に取り付けられます。', 3310, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-ST1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 160, 310, 80.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-SM1', 'サイドボックスミニ', '1回路用。カベ白。既設の住宅用分電盤への追加や組み合わせに使用します。IH調理器、EV充電コンセント等の増設などに最適です。1回路用(MP-SM1)を設置後、再増設する際に既存配線そのままで、2回路用(MP-SM2)を設置することができます。30AFの漏電遮断器又は安全ブレーカーに適用。', 1480, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-SM1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 48, 151, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-SM2', 'サイドボックスミニ', '2回路用。カベ白。既設の住宅用分電盤への追加や組み合わせに使用します。IH調理器、EV充電コンセント等の増設などに最適です。1回路用(MP-SM1)を設置後、再増設する際に既存配線そのままで、2回路用(MP-SM2)を設置することができます。30AFの漏電遮断器又は安全ブレーカーに適用。', 1960, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-SM2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 94, 151, 40);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-SEV', 'サイドボックス(EV・PHV充電用)', 'ミルキーホワイト色。EV・PHVの充電用ブレーカーボックスです。サイドボックス(MP-ST1)に小型ELBを組み込んだ製品です。ELB: 20A 100V 15mA。', 14500, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-SEV', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 160, 310, 80.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MP-SEV2', 'サイドボックス(EV・PHV充電用)', 'ミルキーホワイト色。EV・PHVの充電用ブレーカーボックスです。サイドボックス(MP-ST1)に小型ELBを組み込んだ製品です。ELB: 20A 200V 15mA。', 15800, 'https://dummyimage.com/200x200/cccccc/000.png&text=MP-SEV2', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 160, 310, 80.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MWN-9G9GEMK', '防雨形抜止接地ダブルコンセント (アースターミナル付)', 'マットブラック。機能美を追求した防雨形配線器具です。扉付抜止形コンセントで雨の飛沫、ホコリなどの侵入を防止します。2PE 15A/125V。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=MWN-9G9GEMK', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 87, 123.2, 80.5);
