INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'CTA-N', '盗難見張りアラーム', '二つのセンサーが人や振動をキャッチし、警報アラームとLEDランプで侵入者を威嚇します。配線不要。乾電池式なので設置場所を選びません。ベルトで固定。設置が容易です。(面ファスナー付)簡易防水。(しぶきがかかる程度)。面ファスナー(長さ500mm)付属。', 17900, 'https://dummyimage.com/200x200/cccccc/000.png&text=CTA-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 112.4, 112.4, 35.1);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-1M', 'プロテクトカバー (屋内用スリム) L型プラグ用', 'ミルキーホワイト。冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。自己消火性で、スパークしても火花や火炎を外には出しません。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。二連用・リモコン用は南京錠が取り付けられます。ノックを折り取ると、L型プラグを差した状態で、カバーを閉められます。一連用。', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-1M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 91, 138, 75);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-1K', 'プロテクトカバー (屋内用スリム) L型プラグ用', '黒。冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。自己消火性で、スパークしても火花や火炎を外には出しません。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。二連用・リモコン用は南京錠が取り付けられます。ノックを折り取ると、L型プラグを差した状態で、カバーを閉められます。一連用。', 1160, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-1K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 91, 138, 75);
