INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'WBKS-RM', 'プロテクトカバー (屋内用スリム) リモコン用', 'ミルキーホワイト。冷蔵庫、エアコン等の常設のコンセントに最適です。スリムな設計なので、コンセントスペースが狭い箇所に最適です。(L型プラグ使用)L型プラグ用は埃が入りにくく、トラッキング火災防止に最適です。自己消火性で、スパークしても火花や火炎を外には出しません。カバー付なので、スイッチを取り付けた場合の誤操作防止にもなります。二連用・リモコン用は南京錠が取り付けられます。リモコン用。対応機種(サイズ): エアコン・給湯器(120×120)。', 2080, 'https://dummyimage.com/200x200/cccccc/000.png&text=WBKS-RM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 122, 138, 75);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AFDK-150D', 'ダクトノバース', 'アルミフリーダクトを簡単・キレイにダ円に変形しながら、伸ばすことができる工具です。ダ円に変形させることにより、狭い箇所での施工も容易にできます。100mm程度の狭い箇所での施工が可能です。高さ100mmのダ円に変形させることができますので、φ150では通せなかった(通しにくかった)狭い箇所での施工も容易に行えます。適合管: アルミフリーダクト (150)。', 11200, 'https://dummyimage.com/200x200/cccccc/000.png&text=AFDK-150D', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 275, 318, 160);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AFDK-S', 'ダクトノバース (正円タイプ)', 'アルミフリーダクトを1人で簡単・キレイに伸ばすための工具です。120mm×120mm以下の柱等に括り付けて使用します。適合管: AFD-(75,100N,150,200,250,300)。', 5490, 'https://dummyimage.com/200x200/cccccc/000.png&text=AFDK-S', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KSP-16W', '化粧プレート (電線管用)', 'カベ白。打ち放しのスラブや、天井ボードから出ている電線管の貫通部を化粧するプレートです。分割式なので施工後でもラクに取り付けできます。ビス止め不要!ストッパーにより押し込むだけで簡単に取り付けられます。VE管 16。', 180, 'https://dummyimage.com/200x200/cccccc/000.png&text=KSP-16W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 60, 22, 60);
