INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KHC-B', '仮保持クリップ', '吊りボルトにハンガー等を仮保持する場合に使用します。吊りボルトに挟み込むだけの簡単取り付け。磁石付なので、ハンガー等が滑り落ちにくくなっています。(段差付なのでさらに安心)。2個1組。適合ボルト: W3/8-W1/2。', 2370, 'https://dummyimage.com/200x200/cccccc/000.png&text=KHC-B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 32, 85, 36);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'GGK-12', 'コンパネ固定具(鋲打機用)', '鋲打機でコンパネを取り付ける場合に使用します。木ねじで固定できます。切り欠き部をカットすれば、壁際にも固定できます。許容静荷重:20N (2kgf)。適合コンパネ厚:12~12.5mm。入数:10。', 73, 'https://dummyimage.com/200x200/cccccc/000.png&text=GGK-12', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 62.5, 33, 15.5);
