INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TTA-450', '天井点検口 (屋内専用)', '目地隙間ができず、チリやホコリが落ちにくい構造です。ハンガーがスライドするので取り付け位置が自由です。枠:アルミ製。取付ボード厚:3~29mm。天井施工開口寸法:455×455。L:465。入数:1。', 6760, 'https://dummyimage.com/200x200/cccccc/000.png&text=TTA-450', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 465, 465, NULL);
