INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'KC-L', '蛍光灯用ビニルカバー', '施工時の蛍光灯汚れ防止に使用します。ゴムヒモ、取付板。適合(蛍光灯):富士型(40W×1灯・40W×2灯・40W×3灯), 笠なし型(40W×1灯・40W×2灯), 反射笠付(40W×1灯・40W×2灯・40W×3灯), 片反射笠付(40W×1灯)。入数:10。', 580, 'https://dummyimage.com/200x200/cccccc/000.png&text=KC-L', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 1800, 340, NULL);
