INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LBG-1W', '電球ガード (ゴムソケット用)', '仮設照明の電球保護に使用します。側面のビス穴を使用すれば、壁面、ダウンライト穴(天井)等を利用して振れ止めができます。使用電球(100W用)。色:白。d:37。入数:20組。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=LBG-1W', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 124, 140, NULL);
