INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LBG-S1', '電球ガードスペーサー', '電球ガード(ゴムソケット用)にソケット径φ33を取り付ける場合の径調整に使用します。接着テープ付。適合ソケット径:φ33。適用:電球ガード・ゴムソケット用(取付径:37)。入数:20。', 48, 'https://dummyimage.com/200x200/cccccc/000.png&text=LBG-S1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 105, 22, 7);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCC-38', '三角コーンキャリー® (三角コーン用肩掛け運搬具)', '三角コーンを一度に6個持ち運びができる運搬具です。肩掛けなので両手が使え、同時にコーンバーや重りなどを持ち運べます。ベルトは本体に巻いて収納するので軽量でかさばりません。本体のパイプ(VE22)の長さを変えることで大きさの違う三角コーンも使用できます。適用:三角コーン(最大積載量:6個)。入数:1。', 6920, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCC-38', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 450, 914, 398);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SCC-CT', '三角コーンキャリー用 キャスター (4個1組)', '三角コーンキャリーを引いて運搬する時に使用します。キャスターを三角コーンキャリーのエルボ裏面にあるビス穴を使用し、取り付ける。ビス16本付。許容静荷重:80N(8.1kgf)/個 (※4個取付時は256N (26kgf)まで)。適用:三角コーンキャリー(SCC-38)。入数:1組。', 2260, 'https://dummyimage.com/200x200/cccccc/000.png&text=SCC-CT', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AIA-100', '風速増強アタッチメント (シロッコファン(多翼送風機)専用)', '工場などの空調用パイプに取り付けることで空調の風速を上げることができます。(風速が上がることで、涼しく快適に作業が行えます。)アタッチメントの性能、アタッチメント無/付の風速比較表あり。適合ダクトサイズ:100。適合管サイズ:内径98.5、外径102~107。開口面積:9.3㎡。D:111。d:98.3。入数:1。', 2560, 'https://dummyimage.com/200x200/cccccc/000.png&text=AIA-100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 111, 63, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AIA-150', '風速増強アタッチメント (シロッコファン(多翼送風機)専用)', '工場などの空調用パイプに取り付けることで空調の風速を上げることができます。(風速が上がることで、涼しく快適に作業が行えます。)アタッチメントの性能、アタッチメント無/付の風速比較表あり。適合ダクトサイズ:150。適合管サイズ:内径148.5、外径153~157。開口面積:50.7c㎡。D:161。d:148.3。入数:1。', 3700, 'https://dummyimage.com/200x200/cccccc/000.png&text=AIA-150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 161, 63, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DBC-1', 'チェアバッグ', '折りたたみパイプチェアと大容量バッグが合体!現場でもレジャーでも重宝します。バッグには工具を入れる巨大ポケットがあり、バッグ内側には図面や書類(A4迄)等を入れられます。バッグ内スペースは、使い勝手のよい仕切りが多数ありますので便利です。※スマホ・手帳・ペンなど、文房具を小分けできる小物スペース、A4のカタログや小物を入れられるスペースに分かれています。重量:2.3kg。耐荷重:椅子:833N(85kgf)。収納重量:10kgまで。容量:①外ポケット:約8.5ℓ、②内部容量:約11ℓ。入数:1。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=DBC-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'LX003', 'レバーブロック® (ラチェットレバー付チェーンブロック)', '超小型、軽量で持ち運びに便利。狭い場所や高所作業もラクです。強靭で耐食性・耐摩耗性に優れたニッケルメッキチェーンを採用。はずれ防止付フックラッチだから安心して作業できます。※揚程2m、3m、4mタイプも特注品にて承ります。製造元:株式会社キトー。「レバーブロック」は(株)キトーの登録商標です。定格荷重:250kg。標準揚程:1.0m。自重:1.6kg。入数:1。', 34000, 'https://dummyimage.com/200x200/cccccc/000.png&text=LX003', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 88, 205, 73.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AFP-SH20MSY', 'アルミフレーム用部材 スプレーホルダー (超・強力磁石付)', 'アルミフレームに鉄製スプレー缶を保持させる場合に使用します。アタッチメントをアルミフレームの溝に差し込み、時計回りに90度回転させ取り付けます。適合アルミフレーム溝寸法:20。適合:φ70以下・1kg以下の鉄製スプレー缶。入数:1。', 3080, 'https://dummyimage.com/200x200/cccccc/000.png&text=AFP-SH20MSY', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 107, NULL);
