INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AFP-C16M3K', 'アルミフレーム用部材 ケーブルクリップ', 'アルミフレームにケーブルを保持させる場合に使用します。適合アルミフレーム溝寸法:30。適合ケーブル径:φ15~17(1本)。入数:10。', 70, 'https://dummyimage.com/200x200/cccccc/000.png&text=AFP-C16M3K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AIAF', '風速増強アタッチメント (扇風機用)', '扇風機をサーキュレーターとして使用したり、扇風機の風の届く範囲を広げることができるので空気の循環、洗濯物の部屋干し、広範囲清涼などに最適です。家庭用扇風機(羽根直径30cm)に吸盤で簡単に取り付けられます。適合:家庭用扇風機(羽根直径30cm)。入数:1。', 3170, 'https://dummyimage.com/200x200/cccccc/000.png&text=AIAF', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 260, 140, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BG-TKH-K', '立て掛けホルダー', '長尺物を立て掛ける場合に便利な簡易型ホルダーです。イスや介護用ベッドに取り付けることにより、杖や傘等を身近に置くことができます。カラーバンド(面ファスナー)や紐を通し対象物に取り付けます。側面の突起部を穴にはめ込むと連結ができます。裏面に市販のマグネットシートを貼り、スチール製物置等に取り付けることもできます。入数:1。', 1000, 'https://dummyimage.com/200x200/cccccc/000.png&text=BG-TKH-K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 90, 210, 80);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MRS1', 'マルチロッドスタンド', '遊漁船やプレジャーボート等へ複数の釣り竿を持ち込み、保管する際に便利な自立式のロッドスタンドです。樹脂製なので濡れてもOK!持ち運びも簡単で、船上等に設置しやすい形状です。ジギングロッドやキャスティングロッド等のグリップ部分が長いロッドにも対応しています。ロッドは8本まで保管可能です。リールを付けたままスタンドに差し込めます。リールの回転防止、リールフットの傷付き防止をするパイプキャップ付。パイプキャップにルアー等の針(フック)等を引っ掛けて固定可能です。スタンド中央部の溝にプライヤー、ナイフ等の工具やペットボトルを差し込んでおくことが可能です。製品は組み立て式でコンパクトに収納可能です。組み立ても簡単です。ベース裏面には滑り止め用ゴムパット付です。転倒、防風対策に、ベースに水等を入れて重りにすることが可能です。セット内容:ベース×1個、スタンド×4個、おねじ×4個、ナット×4個、ゴムパット×4個、カバー×1枚。スタンド穴径:φ40。重量:6kg(注水時:約10kg)。入数:1。', 22800, 'https://dummyimage.com/200x200/cccccc/000.png&text=MRS1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 330, 520, 456);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AMS-1', '雨漏りサポート®', '天井の水漏れ箇所に取り付け、ドレンホースにて雨水を排水します。吸盤で取り付けるだけの簡単施工。ビニルシート等に比べ美観が良く水漏れの状態も確認できます。繰り返し使用できます。※吸盤が付かない材質等には、付属の吸盤テープを取り付け箇所に貼り、そのテープに吸着固定します。セット内容:本体×1、排水アダプター(ストレート)×1、排水アダプター(45)×1、ねじ式吸盤×2、ねじ式吸盤用テープ×2。ドレンホース:サイズ14。入数:1。', 11600, 'https://dummyimage.com/200x200/cccccc/000.png&text=AMS-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 576, 576, NULL);
