INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AMS-ASV', '雨漏りサポート用ドレン配管アダプター', '雨漏りサポートに取り付けたドレンホースを排水管に接続する場合に使用します。ドレンホース:サイズ14。排水管:VP75,100, VU75,100,125,150,200。入数:1。', 1860, 'https://dummyimage.com/200x200/cccccc/000.png&text=AMS-ASV', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SSF-33', 'スワローサポート® (壁用)', 'ツバメの糞受けです。ツバメの巣から少し下に設置し、通行する人にツバメの糞が当たらないようにします。組み立て式で、90°、180°に対応しています。※SSF-33は、360°にも対応できます。(製品2つ必要です)。入数:1。', 3390, 'https://dummyimage.com/200x200/cccccc/000.png&text=SSF-33', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 360, 265, 45);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SSF-40', 'スワローサポート® (壁用, 交換タイプ)', 'ツバメの糞受けです。ツバメの巣から少し下に設置し、通行する人にツバメの糞が当たらないようにします。組み立て式で、90°、180°に対応しています。SSF-40は、糞受け部を交換するタイプです。(90度糞受け4枚付)。入数:1。', 3390, 'https://dummyimage.com/200x200/cccccc/000.png&text=SSF-40', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 423, 216, 100);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SSF-FL1', 'スワローサポート® (フロアシート, 桜)', '学校や公共施設、店舗等の燕巣下に設置し、ツバメの巣からの糞を床で受け止めるシートです。底面の粘着テープで床(壁)に貼り付け固定するタイプです。デザインは選べる4タイプ。厚紙製。※紙にポリプロピレンをコートしてあります。※汚物が付着するため、リサイクル用紙としては使用できません。デザイン:桜。入数:1。', 3030, 'https://dummyimage.com/200x200/cccccc/000.png&text=SSF-FL1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 600, 900, NULL);
