INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-L2SV100', '水田当番(キット品)', '水位計(AGST-LG2)・止水栓(100用)のセット。設定可能水位は5cm~20cm。電源不要。100サイズは水路から圃場への雑草やごみの侵入を防ぐ止水栓フィルターも付属。止水栓の口が広く、ごみ詰まりしにくい。止水状態がわかる旗付き。水路内水位と止水栓の高低差が500mm以上になる場合は使用不可。', 18600, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-L2SV100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
