INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-LG2LW', '水田当番用水位計交換ワイヤー', 'ワイヤー長さ: 2m。水田当番用水位計のワイヤーを破損した場合やワイヤーの長さを変更する場合に使用する交換用部材。適合: 水田当番用水位計。', 3000, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-LG2LW', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-KG', '簡易水位計', '田んぼの水位が簡単に目視確認できる水位計。添付のカラーシールを貼れば、遠くからでも水位が一目瞭然。3箇所折り曲げて使用。手で簡単に折り曲げられる。固定が不安な場合は、杭(MFU-30S等)を取り付けてください。計測水位: 0~15cm。', 1340, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-KG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-TE1', '水田当番用タイマー', '水田当番用止水栓に取り付けて使用。設定した時間が経過すると止水栓の弁が閉じ、水が止まる。日中の強い日差しでも見やすい緑色の高輝度LEDを使用。止水時間は、1時間刻みで設定可能。止水栓へねじ込むだけの簡単取り付け。電源:単三アルカリ乾電池×4本(別売)。常にタイマー全体が水没するような場所には設置しないでください。タイマーが水没するような場所に設置する場合は、別売の延長アタッチメントをご使用ください。適合: AGST-SV100-AGST-SV150。', 18700, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-TE1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 167, 164, 167);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-TE1A', '延長アタッチメント', 'ワイヤー長さ: 2m。水田当番用タイマーを止水栓から離れた場所に設置できる延長アタッチメント。タイマーを杭に取り付けることもできる。適合: AGST-TE1。', 2500, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-TE1A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-AR100', '回転アダプター', 'エルボを使った水管理時に使用。エルボの回転を良くする補助部材。取っ手を持つ又はパイプ等を使用することで簡単にエルボを回転できる。パイプ(VP管等)を使用すれば、かがまずエルボを回せる。適合パイプサイズ: Φ26以下 (VP管:20, 農業用支柱:Φ20)。パイプ径: VU管(100)。適合エルボ: DV・DLエルボ(100)。', 1870, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-AR100', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGST-MCV150', '水口調整板', '水口がU字溝の場所で使用できる堰板。U字溝の幅が240~400mm迄対応。水口から流入する水量を調整できる(6段階に調整可能)。水田当番用止水栓(AGST-SV150)を取り付け可能。本体のくぼみに蓋を引っ掛けることで水路の開閉具合を変更できる。適合: AGST-SV150。', 4820, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGST-MCV150', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGUG-SES', '水路調整堰板', 'U字溝に使用する水深調整板。溝のサイズ・水の深さに合わせて調整し、置くだけの簡単施工。4サイズ(7種類)の水路に適合。主材に発泡PVCを使用しているので軽く、移動が楽。水をせき止め、水位をあげることができる。適合: ベンチフリューム1種(農業用の水路) サイズ: 200-250、U形側溝(道路脇の水路) サイズ: 180-240。調整幅: 165~245mm。', 5180, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGUG-SES', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGUG-SEM', '水路調整堰板', 'U字溝に使用する水深調整板。溝のサイズ・水の深さに合わせて調整し、置くだけの簡単施工。4サイズ(7種類)の水路に適合。主材に発泡PVCを使用しているので軽く、移動が楽。水をせき止め、水位をあげることができる。適合: ベンチフリューム1種(農業用の水路) サイズ: 300-350、U形側溝(道路脇の水路) サイズ: 300 (A.B.C) 360(A.B)。調整幅: 260~340mm。', 5260, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGUG-SEM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGUG-SEVM', '水路調整堰板', 'U字溝に使用する水深調整板。溝のサイズ・水の深さに合わせて調整し、置くだけの簡単施工。4サイズ(7種類)の水路に適合。主材に発泡PVCを使用しているので軽く、移動が楽。水をせき止め、水位をあげることができる。適合: Vトラフ サイズ: 300×300-300×400。調整幅: 上側:410~490mm、下側:260~340mm。', 8160, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGUG-SEVM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGH-SS10', '排水革命® 堰板(せきいた)', '排水桝専用の仕切板。スライド式で様々な排水桝に設置可能。重ねて使用すれば高さ調整可能。樹脂製なので腐食しにくく長く使える。堰板高さ:100mm。適合水田用排水桝(溝サイズ): 溝厚15mm以上、溝幅200~310mm。', 2280, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGH-SS10', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, 100, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGH-CLS', '排水革命® 調整堰板(エルボタイプ)', '排水桝専用の仕切板。水田の土留め、止水、水位調整が可能。樹脂製なので腐食しにくく長く使える。排水桝のサイズに合わせたサイズでお作りする。エルボを回転させることで排水する水位の調整が可能。エルボサイズ: 75。設定可能水位: 0~130mm。縦: 300~600mm, 横: 200~300mm, 田面高さ: 70~330mm。', 21400, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGH-CLS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGH-CLM', '排水革命® 調整堰板(エルボタイプ)', '排水桝専用の仕切板。水田の土留め、止水、水位調整が可能。樹脂製なので腐食しにくく長く使える。排水桝のサイズに合わせたサイズでお作りする。エルボを回転させることで排水する水位の調整が可能。エルボサイズ: 100。設定可能水位: 0~170mm。縦: 400~600mm, 横: 301~400mm, 田面高さ: 125~315mm。', 26500, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGH-CLM', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGD-AV150A', 'ラクダム VUアダプター', '水田に田んぼダム機能を持たせるための製品。排水桝のVU管にはめて使用するので桝幅に合わせて堰板をカットするなどの手間が不要。水管理の邪魔にならない形状。オーバーフロー機能(余水吐)があるので、水田が満水になった場合に畦を壊す心配がない。排水桝よりも50mm程度低くなるように製品をカットし、排水桝のVU管に製品をはめ込む。排水口(Φ50)からゆっくり排水。適合水田用排水桝: 高さ300~650mm、幅200mm以上。パイプ径: VU150。', 2500, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGD-AV150A', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGH-CS', '排水革命® 調整堰板(せきいた)', '排水桝専用の仕切り板。スライド式で様々な排水桝に設置可能。縦にスライドすることで、高さ調整可能。樹脂製なので腐食しにくく長く使える。堰板高さ:150~250mm。適合水田用排水桝(溝サイズ): 溝厚15mm以上、溝幅200~310mm。', 3500, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGH-CS', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MSRB-105', '目地スペーサー (レンガ、ブロック用)', 'レンガで花壇などを作る際の目地を簡単、綺麗に作るための補助部材。目地の高さ、幅、奥行きを簡単に一定間隔確保。シートの状態から折り取り、組み合わせて使用。横目地用スペーサーとして使用する場合、上の段のレンガの重みでモルタルが潰れることなく目地の高さ(10mm)を揃えることができる。目地枠(両側用)として使用する場合、モルタルの量が一定にでき、目地の奥行き、高さを揃えることができる。適用: レンガ・ブロック用。', 410, 'https://dummyimage.com/200x200/cccccc/000.png&text=MSRB-105', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DIYA-19M', 'シェルフィーヌ®(角度調整可能な棚板受け)', '色: ミルキーホワイト。市販のワンバイ材(1×4)で棚を作る時に棚受けとして使用。用途に合わせ、棚の角度が簡単に変えられる。高耐久、高耐候素材を使用しているので、屋外もOK。多肉植物の育成にピッタリ。台座の角度は6段階に調整可能。背面固定だけでなく、側面でも固定可能。木ねじ(3.8×38)×4、木ねじ(3.8×51)×2、木ねじ(3.8×25)×4 (ステンレス製)が付属。適用ワンバイ材: 底板: 1×4~1×8材、前板: 1×2~1×4材。', 2440, 'https://dummyimage.com/200x200/cccccc/000.png&text=DIYA-19M', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 145.5, 89.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'DIYA-19K', 'シェルフィーヌ®(角度調整可能な棚板受け)', '色: アイアンブラック。市販のワンバイ材(1×4)で棚を作る時に棚受けとして使用。用途に合わせ、棚の角度が簡単に変えられる。高耐久、高耐候素材を使用しているので、屋外もOK。多肉植物の育成にピッタリ。台座の角度は6段階に調整可能。背面固定だけでなく、側面でも固定可能。木ねじ(3.8×38)×4、木ねじ(3.8×51)×2、木ねじ(3.8×25)×4 (ステンレス製)が付属。適用ワンバイ材: 底板: 1×4~1×8材、前板: 1×2~1×4材。', 2440, 'https://dummyimage.com/200x200/cccccc/000.png&text=DIYA-19K', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 35, 145.5, 89.5);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGM-H1', '苗箱用ハンドル', '播種作業時の運搬作業をラクに行うための苗箱用のハンドル。苗箱移動時の指先の負荷による痛みや、苗箱を積む際に指を挟んでしまうといったことが解消できる。シッカリ握れるので指先に負荷がかからない。ハンドル2個に農業用支柱を取り付ければ、腰をかがめずに苗箱の移動ができる。持ち運び可能な苗箱は3段まで。苗箱端部の形状によってはフックが引っかからず、使用できない場合がある。バンド: 無。', 1280, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGM-H1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'AGM-H1B', '苗箱用ハンドル (バンド付)', '播種作業時の運搬作業をラクに行うための苗箱用のハンドル。苗箱移動時の指先の負荷による痛みや、苗箱を積む際に指を挟んでしまうといったことが解消できる。腕への負担軽減やハンドルの落下防止ができるバンド付。バンド幅25mm。シッカリ握れるので指先に負荷がかからない。ハンドル2個に農業用支柱を取り付ければ、腰をかがめずに苗箱の移動ができる。持ち運び可能な苗箱は3段まで。苗箱端部の形状によってはフックが引っかからず、使用できない場合がある。バンド: 付。', 1960, 'https://dummyimage.com/200x200/cccccc/000.png&text=AGM-H1B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TT-NKB', 'ねじ式吸盤(台座)', '飛沫感染防止パーテーションが簡単に設置できる台座。アクリル板、VE管を利用した衝立を台座に差し込むだけ。吸盤タイプなので取り付け、取り外しが容易。アクリル板2、3mmを取り付ける場合は、ボード支持具を使用し隙間を埋める。吸盤が取り付かない材質等の場合は、吸盤用テープを取り付け面に貼り付け、その上に吸盤を付ける。適合: アクリル板(厚さ2、3、4mm)、VE管Φ14付属品。', 3640, 'https://dummyimage.com/200x200/cccccc/000.png&text=TT-NKB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 77, 101, 77);
