INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'TSB-50-400', '打ち込みスリーブ(免震ピット 擁壁用貫通スリーブ)', '免震建物での擁壁及び地中梁にケーブルを通す場合の貫通スリーブとして使用します。制約がある壁面積に近接させて打ち込めるスリーブ形状により、多くの管が配管できます。擁壁(地中梁)の厚みに合わせて長さ調整ができます。カクフレキやミラレックス(F)、VE管との接続が容易です。埋設管サイズと同じ呼びで接続できますから口径が上がることなく、余分な補強筋を入れる手間がありません。地下からの水浸入を防ぐ、シールテープ付です。オール樹脂製ですから、錆が発生しません。養生キャップ付。(本体と型枠との固定機能付です。)適合壁厚200~400mm。カクフレキ用KFEKH-50BA、ミラレックス用MFKH-54BA、ミラレックスF用FEKH-50BA、塩ビ管VE54適合。', 3380, 'https://dummyimage.com/200x200/cccccc/000.png&text=TSB-50-400', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 80, 395, 73);
