INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'BKH-75', 'ボイドハンガー®', '鉄筋やボルトにボイド管や塩ビ管等を固定する場合に使用します。結束バンドタイプなので、幅広いボイド径に対応し簡単確実に取り付けられます。鉄筋へのコンクリートのかぶり厚(40mm、50mm、60mm)を確保できます。好きな長さに切断して使用できるキット品とボイドハンガー本体、結束バンドの単品売りもあります。スリーブ結束部分は樹脂製なので錆の発生がありません。', NULL, 'https://dummyimage.com/200x200/cccccc/000.png&text=BKH-75', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 16, 21, NULL);
