INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MKPB-B', '防水用ボルト (マンホール蓋用)', '簡易防水型マンホール蓋を密閉型にする場合に使用します。マンホール蓋の蓋と枠の間からの水の浸入を防止することができます。マンホール蓋を土中に施工した後からでも取り付けができます。セット内容:六角袋ナット:M8(M12)×4, シール座金:呼び8(呼び12)×4, 六角ナット:M8(M12)×4, 六角ボルト:M8×40(M12×40)×4.', 1260, 'https://dummyimage.com/200x200/cccccc/000.png&text=MKPB-B', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
