INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), '150P', '浮上防止プレート (ミライハンドホール用)', '湿地帯への埋設時でハンドホールの浮上防止に使用します。穴加工不要! ミライハンドホールの側面リブにボルト・ナットで固定するだけです。150P、200P・3045Pはタッピンねじで固定するだけです。アンカー取付穴が設けてあります。', 4970, 'https://dummyimage.com/200x200/cccccc/000.png&text=150P', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 350, 3.2, 350);
