INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'SFAP-1', 'プラステロック®', 'マンホール蓋の開閉行為等のいたずら防止、歩行者のつまずき防止等に使用します。FRP製マンホール蓋には取り付けられません。結束バンド固定なので容易には取り外せません。', 1020, 'https://dummyimage.com/200x200/cccccc/000.png&text=SFAP-1', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 38, 19.5, 3.7);
