INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MHR-3045', 'ミライハンドホール (丸型) (樹脂製)', '樹脂製なので軽量で持ち運び、施工がラクに行えます。丸型なので360°どの方向にも配管(コネクタ取り付け)ができます。仕切板を取り付ければ、強電と弱電の隔離ができます。丸型キット品は、パイプ無しの組み立てタイプです。市販のVU管を自由な長さに切断し、現場に合わせたハンドホールが作れます。車両等が乗らない場所に設置してください。', 26800, 'https://dummyimage.com/200x200/cccccc/000.png&text=MHR-3045', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 415, 524, 415);
