INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MKPBR-300', 'マンホール蓋 (丸型) 簡易密閉型「電気」の表示入り', 'ミライハンドホール(丸型)のマンホール蓋として使用します。FRP製なので、強靭で軽く、持ち運びや取り扱いがラクに行えます。防水用ボルトを取り付けることで密閉型として使用できます。鎖付。蓋と枠が連結できます。', 25000, 'https://dummyimage.com/200x200/cccccc/000.png&text=MKPBR-300', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 410, 5, 410);
