INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MPT-GE330', 'エポキシパテ (1液タイプ)', 'ハンドホールへのコネクタ取り付け時の防水に最適です。混合不要の1液常温硬化形で作業性に優れています。弾力性に富み、衝撃吸収性、材料収縮時の追従性があります。各種被着材(コンクリート、モルタル、塩化ビニル樹脂)の接着に適しています。色(グレー)。容量: 330ml, 入数: 1。', 2040, 'https://dummyimage.com/200x200/cccccc/000.png&text=MPT-GE330', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MPT-E10-N', 'エポキシパテL', '強力な接着効果があり、特にコンクリートと塩ビ製品との固定に最適です。管の壁貫通部の固定や防水、付属品の防水性向上に最適です。主剤と硬化剤1:1で混ぜ合せるだけの使い易い等量混合タイプです。夏用と冬用があります。速乾タイプは急速乾燥し、速効性に優れます。色:主剤/白、硬化剤/暗灰色、混合後/灰色。ビニール手袋入・混合ヘラ入。種類: 夏用, 容量(セット内容): 10kg(主剤5kg・硬化剤5kg), 入数: 1セット。', 19400, 'https://dummyimage.com/200x200/cccccc/000.png&text=MPT-E10-N', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', NULL, NULL, NULL);
