INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MFSE-16CG', 'エンドカップリング (PF管用) スクリュー釘付 Gタイプ グレー色', '適合サイズ: 埋設側 PF管16, 露出側 PF管16。エンドカバーとカップリングがドッキング! コンクリート打設後の接続が簡単になりました。二重天井への引き込み等に使用します。付属の釘1本で固定できます。(打設後、釘は簡単に外せます。)接続も解除も一発でOK!トロ防止シール付です!底面にネームシール等が貼れます。', 240, 'https://dummyimage.com/200x200/cccccc/000.png&text=MFSE-16CG', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64.4, 57.8, 150);
