INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MFSE-22WPGA3', 'プラスエンド® (PF管用) Gタイプ ベージュ色 アンカー付', '適合管: PF管16-22。送り配管による感知器等の取り付けに使用します。通常の送りエンドよりエンド内のスペースが大きくとれ、配線し易い形状です。コネクタの取り付けによってL・T・X形に配管が可能です。22サイズは付属の変換アダプタを使用して16サイズの管を配管できます。Gタイプだから管の接続解除も一発でOK!トロ防止シール付です。アンカー付は、VVFケーブルの二重天井への引き込みによる照明器具等の重量物直接取り付けに使用します。', 420, 'https://dummyimage.com/200x200/cccccc/000.png&text=MFSE-22WPGA3', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64, 77, 121);
