INSERT INTO materials (manufacturer_id, model_number, name, description, standard_price, image_url, catalog_url, width_mm, height_mm, depth_mm) VALUES ((SELECT id FROM manufacturers WHERE name = '未来工業' LIMIT 1), 'MFSE-22WPGKB', 'プラスエンド® (ボックスタイプ・PF管用) Gタイプ (M4ナット圧入品)', '適合管: PF管16・22 (MF、MFXは除く)。送り配管による感知器等の取り付けに使用します。通常の送りエンドよりエンド内のスペースが大きくとれ、配線し易い形状です。本体にM4ナット (66.7ピッチ)が圧入されているので、引掛けローゼットを介して照明器具等(天井直付け器具以外)の吊り下げが行えます。コネクタの取り付けによってL・T・X形に配管が可能です。付属の変換アダプタを使用して16サイズの管を配管できます。Gタイプだから管の接続解除も一発でOK!トロ防止シール付です。スクリュー釘を打ち込むだけで固定できます。', 560, 'https://dummyimage.com/200x200/cccccc/000.png&text=MFSE-22WPGKB', 'https://drive.google.com/file/d/1_I6GkKufTjty5moo9Ba7kWrUsCgFy7i5/view?usp=drive_link', 64, 77, 121);
